  });
  const labelStyle = styleMap({ display: "flex", alignItems: "center", cursor: "pointer", gap: `${MODAL_INNER_GAP_PX}px` });
  return copyPasteSellOptionTemplate({
    boxStyle,
    labelStyle,
    inputStyle: styleMap({ margin: 0 }),
    checked,
    onSellChange,
    textStyle: styleMap({ color: COLOR_GOLD }),
    text: `Sell existing grid for $${fmt(currentSellValue)}`,
  });
}

function renderModalCostContent(modalCost, cost, summary, ui, options, onSlotClick) {
  const componentTemplate = summary.length ? renderComponentIcons(summary, options, onSlotClick) : html``;
  const costTemplate = cost > 0 ? html`<div style=${styleMap({ marginTop: `${MODAL_COST_MARGIN_TOP_PX}px`, color: COLOR_SUCCESS, fontWeight: "bold" })}>Total Cost: $${fmt(cost)}</div>` : html``;
  render(copyPasteModalCostContentTemplate({ componentTemplate, costTemplate }), modalCost);
}

function syncModalDialogOpen(root, open) {
  if (!root || typeof HTMLDialogElement === "undefined" || !(root instanceof HTMLDialogElement)) return;
  try {
    if (open && !root.open) root.showModal();
    else if (!open && root.open) root.close();
  } catch (_) {}
}

export function getCopyPasteRefs(root = document.getElementById("modal-root")) {
  if (!root) return null;
  const modal = root.querySelector("#reactor_copy_paste_modal");
  const modalTitle = root.querySelector("#reactor_copy_paste_modal_title");
  const modalText = root.querySelector("#reactor_copy_paste_text");
  const modalCost = root.querySelector("#reactor_copy_paste_cost");
  const closeBtn = root.querySelector("#reactor_copy_paste_close_btn");
  const confirmBtn = root.querySelector("#reactor_copy_paste_confirm_btn");
  if (!modal || !modalTitle || !modalText || !modalCost || !closeBtn || !confirmBtn) return null;
  return { modal, modalTitle, modalText, modalCost, closeBtn, confirmBtn };
}

export function openCopyPasteDialogHost() {
  const root = document.getElementById("modal-root");
  if (!root) return null;
  render(copyPasteDialogShellTemplate(), root);
  syncModalDialogOpen(root, true);
  return getCopyPasteRefs(root);
}

function showModal(ui, refs, opts) {
  modalUi.activeModal = MODAL_IDS.COPY_PASTE;
  modalUi.payload = opts;
  const liveRefs = refs ?? openCopyPasteDialogHost();
  if (!liveRefs) return;
  const { modal, modalTitle, modalText, modalCost, confirmBtn, closeBtn } = liveRefs;
  const { title, data, cost, action, canPaste = false, summary = [], ...options } = opts;
  const confirmLabel = action === "copy" ? "Copy" : "Paste";
  modalTitle.textContent = title;
  confirmBtn.textContent = confirmLabel;
  modalText.value = data;
  setModalTextareaVisibility(modalText, action === "paste");
  const wasPaused = !!ui.game.state.pause;
  if (!wasPaused) ui.game.pause();
  renderModalCostContent(modalCost, cost, summary, ui, options);
  if (action === "copy") {
    modalText.readOnly = true;
    modalText.placeholder = "Reactor layout data (read-only)";
    confirmBtn.classList.remove("hidden");
    confirmBtn.disabled = false;
  } else if (action === "paste") {
    modalText.readOnly = false;
    modalText.placeholder = (data && data.trim()) ? "Paste reactor layout JSON data here..." : "Enter reactor layout JSON data manually...";
    confirmBtn.classList.remove("hidden");
    confirmBtn.disabled = !canPaste;
  }
  const previewWrap = document.getElementById("reactor_copy_paste_preview_wrap");
  const partialBtn = document.getElementById("reactor_copy_paste_partial_btn");
  if (previewWrap) previewWrap.classList.toggle("hidden", action !== "paste");
  if (partialBtn) partialBtn.classList.toggle("hidden", action !== "paste");
  modal.dataset.previousPauseState = wasPaused;
  closeBtn.onclick = () => hideCopyPasteModal(ui);
  const dialogRoot = document.getElementById("modal-root");
  if (dialogRoot && !dialogRoot._copyPasteBackdropBound) {
    dialogRoot._copyPasteBackdropBound = true;
    dialogRoot.addEventListener("click", (e) => {
      if (e.target === dialogRoot) hideCopyPasteModal(ui);
    });
  }
}

export function setupCopyAction(ui, { copyBtn, getRefs }) {
  const game = ui.game;

  copyBtn.onclick = () => {
    const refs = getRefs();
    if (!refs) return;
    const { modalCost, confirmBtn } = refs;
    const data = serializeReactor(game);
    const layout = deserializeReactor(data);
    const cost = calculateLayoutCost(game.partset, layout);
    const summary = buildPartSummary(game.partset, layout);
    const checkedTypes = {};
    summary.forEach(item => { checkedTypes[item.id] = true; });

    showModal(ui, refs, { title: "Copy Reactor Layout", data, cost, action: "copy", canPaste: false, summary, showCheckboxes: true, checkedTypes });

    const updateCopySummary = (layout, summary, checkedTypes) => {
      const onSlotClick = (ids, checked) => {
        ids.forEach(id => { checkedTypes[id] = !checked; });
        updateCopySummary(layout, summary, checkedTypes);
      };
      const componentTemplate = renderComponentIcons(summary, { showCheckboxes: true, checkedTypes }, onSlotClick);
      const filteredLayout = filterLayoutByCheckedTypes(layout, checkedTypes);
      const filteredCost = calculateLayoutCost(game.partset, filteredLayout);
      const costTemplate = copyPasteSelectedPartsCostTemplate({
        costStyle: styleMap({ marginTop: `${MODAL_COST_MARGIN_TOP_PX}px`, color: COLOR_SUCCESS, fontWeight: "bold" }),
        text: `Selected Parts Cost: $${fmt(filteredCost)}`,
      });
      render(html`${componentTemplate}${costTemplate}`, modalCost);
      confirmBtn.disabled = false;
      confirmBtn.classList.remove("hidden");
    };

    updateCopySummary(layout, summary, checkedTypes);

    confirmBtn.onclick = async () => {
      if (!game) return;
      const filteredLayout = filterLayoutByCheckedTypes(layout, checkedTypes);
      const rows = game.rows;
      const cols = game.cols;
      const parts = filteredLayout.flatMap((row, r) => (row || []).map((cell, c) => (cell && cell.id) ? { r, c, t: cell.t, id: cell.id, lvl: cell.lvl || 1 } : null).filter(Boolean));
      const compactLayout = { size: { rows, cols }, parts };
      const filteredData = JSON.stringify(compactLayout, null, JSON_INDENT_SPACES);
      const shareCode = encodeLayoutShare(filteredLayout, game.partset);
      const clipboardPayload = shareCode || filteredData;
      const result = await ui.clipboardUI.writeToClipboard(clipboardPayload);
      const defaultName = `Layout ${new Date().toLocaleDateString()} ${new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' })}`;
      const name = (typeof prompt === "function" ? prompt("Name for this layout:", defaultName) : null) || defaultName;
      if (result.success) {
        addToMyLayouts(name.trim() || defaultName, filteredData);
        confirmBtn.textContent = "Copied!";
      } else {
        confirmBtn.textContent = "Failed to Copy";
      }
      setTimeout(() => hideCopyPasteModal(ui), MODAL_HIDE_DELAY_MS);
    };

    confirmBtn.disabled = false;
    confirmBtn.classList.remove("hidden");
    confirmBtn.style.backgroundColor = CONFIRM_BTN_BG;
    confirmBtn.style.cursor = "pointer";
  };
}

function showBlueprintDeficitToast(result) {
  const parts = [];
  if (result.moneyShort > 0) parts.push(`$${fmt(result.moneyShort)}`);
  if (result.epShort > 0) parts.push(`${fmt(result.epShort)} EP`);
  if (parts.length === 0 && result.breakdown) {
    const b = result.breakdown;
    if (b.money > 0) parts.push(`$${fmt(b.money)}`);
    if (b.ep > 0) parts.push(`${fmt(b.ep)} EP`);
  }
  showStatusNotice({
    tag: "Blueprint",
    body: parts.length ? `Need ${parts.join(" + ")} more` : "Not enough resources",
  });
}

function downloadTextFile(filename, text, mime = "text/plain") {
  const blob = new Blob([text], { type: mime });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  a.click();
  URL.revokeObjectURL(url);
}

function tickSeriesToCsv(series) {
  if (!series?.length) return "";
  const headers = Object.keys(series[0]);
  const lines = [headers.join(",")];
  for (let i = 0; i < series.length; i++) {
    lines.push(headers.map((h) => series[i][h]).join(","));
  }
  return lines.join("\n");
}

function queueBlueprintPaste(game, layout, options = {}) {
  game.state.intent_queue.push({
    action: "APPLY_BLUEPRINT",
    payload: {
      layout,
      sellExisting: !!options.sellExisting,
      skipCostDeduction: options.skipCostDeduction === true,
      partial: options.partial === true,
    },
  });
}

function handleConfirmPaste(ui) {
  const g = ui.game;
  const layoutToPaste = deserializeReactorInput(pasteState.textareaData, g);
  if (!layoutToPaste) {
    logger.log('warn', 'ui', 'Please paste reactor layout data into the text area.');
    return;
  }
  const filtered = filterLayoutByCheckedTypes(layoutToPaste, pasteState.checkedTypes);
  const breakdown = calculateLayoutDiffBreakdown(g, filtered);
  const sellCredit = pasteState.sellExisting ? calculateCurrentSellValue(g.tileset) : 0;
  const validation = validatePasteResources(breakdown, sellCredit, g.state.current_money, g.state.current_exotic_particles ?? 0);

  if (!validation.valid) {
    if (validation.reason === "insufficient_resources") {
      const money = typeof g.state.current_money?.toNumber === "function" ? g.state.current_money.toNumber() : Number(g.state.current_money ?? 0);
      const ep = typeof g.state.current_exotic_particles?.toNumber === "function" ? g.state.current_exotic_particles.toNumber() : Number(g.state.current_exotic_particles ?? 0);
      showBlueprintDeficitToast({
        moneyShort: Math.max(0, breakdown.money - sellCredit - money),
        epShort: Math.max(0, breakdown.ep - ep),
        breakdown,
      });
    } else {
      logger.log('warn', 'ui', validation.reason === "no_parts" ? "Invalid layout: no parts found." : "Not enough resources for full layout.");
    }
    return;
  }
  queueBlueprintPaste(g, clipToGrid(filtered, g.rows, g.cols), { sellExisting: pasteState.sellExisting });
  g.engine?.consumeIntentQueueAsync?.().then(() => {
    ui.gridCanvasRenderer?.markStaticDirty?.();
    startRenderLoop(ui, 0);
  });
  hideCopyPasteModal(ui);
}

function handlePartialPaste(ui) {
  const g = ui.game;
  const layoutToPaste = deserializeReactorInput(pasteState.textareaData, g);
  if (!layoutToPaste) return;
  const filtered = filterLayoutByCheckedTypes(layoutToPaste, pasteState.checkedTypes);
  queueBlueprintPaste(g, clipToGrid(filtered, g.rows, g.cols), { sellExisting: pasteState.sellExisting, partial: true });
  g.engine?.consumeIntentQueueAsync?.().then(() => {
    ui.gridCanvasRenderer?.markStaticDirty?.();
    startRenderLoop(ui, 0);
  });
  hideCopyPasteModal(ui);
}

function renderPasteModalContent(ui, refs) {
  const g = ui.game;
  const parsed = deserializeReactorInput(pasteState.textareaData, g);
  if (!parsed) {
    const msg = !pasteState.textareaData ? "Enter reactor layout JSON data in the text area above" : "Invalid layout data - please check the JSON format";
    render(copyPasteStatusMessageTemplate({ message: msg }), refs.modalCost);
    refs.confirmBtn.disabled = true;
    const partialBtnRef = document.getElementById("reactor_copy_paste_partial_btn");
    if (partialBtnRef) partialBtnRef.disabled = true;
    return;
  }

  const originalSummary = buildPartSummary(g.partset, parsed);
  originalSummary.forEach(item => {
    if (pasteState.checkedTypes[item.id] === undefined) {
      pasteState.checkedTypes[item.id] = true;
    }
  });

  const validationState = buildPasteState(parsed, pasteState.checkedTypes, g, g.tileset, pasteState.sellExisting);
  if (!validationState.valid) {
    render(copyPasteStatusMessageTemplate({ message: validationState.invalidMessage }), refs.modalCost);
    refs.confirmBtn.disabled = true;
    const partialBtnRef = document.getElementById("reactor_copy_paste_partial_btn");
    if (partialBtnRef) partialBtnRef.disabled = true;
    return;
  }

  const onSlotClick = (ids, checked) => ids.forEach(id => { pasteState.checkedTypes[id] = !checked; });
  const onSellChange = (e) => { pasteState.sellExisting = e.target.checked; };

  const componentTemplate = renderComponentIcons(originalSummary, { showCheckboxes: true, checkedTypes: pasteState.checkedTypes }, onSlotClick);
  const hasSellOption = refs.modal.dataset.hasSellOption === "true";
  const totalSellValue = Number(refs.modal.dataset.sellValue || 0);

  const sellOptionTemplate = hasSellOption
    ? SellOption({ currentSellValue: totalSellValue, checked: pasteState.sellExisting, onSellChange })
    : html``;

  const costTemplate = CostDisplay({
    breakdown: validationState.breakdown,
    affordability: {
      canAffordMoney: validationState.canAffordMoney,
      canAffordEp: validationState.canAffordEp,
      currentMoneyNum: validationState.currentMoneyNum,
      currentEpNum: validationState.currentEpNum,
    },
  });

  render(
    copyPasteRenderedContentTemplate({
      componentTemplate,
      sellOptionTemplate,
      costTemplate,
    }),
    refs.modalCost
  );

  refs.confirmBtn.disabled = !validationState.canPaste;
  const partialBtnRef = document.getElementById("reactor_copy_paste_partial_btn");
  if (partialBtnRef) {
    partialBtnRef.disabled = !validationState.hasPartial;
  }

  const previewCanvas = document.getElementById("reactor_copy_paste_preview");
  if (previewCanvas) {
    const diff = g ? computeBlueprintDiff(g, validationState.filteredLayout) : { unchanged: [], toPlace: [] };
    const affordableSet = new Set(
      diff.unchanged.map((u) => `${u.r},${u.c}`)
    );
    (validationState.affordablePlacements || []).forEach((p) => affordableSet.add(`${p.r},${p.c}`));
    renderLayoutPreview(g.partset, parsed, previewCanvas, validationState.canPaste ? null : affordableSet);
  }
}

export function setupPasteAction(ui, { pasteBtn, getRefs }) {
  const g = ui.game;

  const bindPasteModalListeners = (refs) => {
    const { modal, modalText, confirmBtn } = refs;
    const partialBtn = document.getElementById("reactor_copy_paste_partial_btn");
    if (modal._pasteListenersBound) return;
    modal._pasteListenersBound = true;
    subscribe(pasteState, () => {
      const liveRefs = getCopyPasteRefs();
      if (liveRefs) renderPasteModalContent(ui, liveRefs);
    });
    modalText.oninput = (e) => {
      pasteState.textareaData = e.target.value.trim();
      pasteState.checkedTypes = {};
    };
    confirmBtn.onclick = () => handleConfirmPaste(ui);
    if (partialBtn) partialBtn.onclick = () => handlePartialPaste(ui);
  };

  ui._showPasteModalWithData = (data) => {
    const refs = getRefs();
    if (!refs) return;
    bindPasteModalListeners(refs);
    const { modal } = refs;
    pasteState.textareaData = data;
    pasteState.checkedTypes = {};
    pasteState.sellExisting = false;

    const layout = deserializeReactorInput(data, g);
    const summary = buildPartSummary(g.partset, layout || []);
    const title = data ? "Paste Reactor Layout" : "Enter Reactor Layout Manually";
    const currentSellValue = calculateCurrentSellValue(g.tileset);
    const hasExistingParts = ui.game.tileset.tiles_list.some(tile => tile.enabled && tile.part);

    modal.dataset.hasSellOption = String(hasExistingParts);
    modal.dataset.sellValue = String(currentSellValue);

    showModal(ui, refs, { title, data, cost: 0, action: "paste", canPaste: false, summary, showCheckboxes: true, checkedTypes: {} });
    renderPasteModalContent(ui, refs);
  };

  pasteBtn.onclick = async () => {
    const result = await ui.clipboardUI.readFromClipboard();
    ui._showPasteModalWithData(result.success ? result.data : "");
  };
}


export class CopyPasteUI {
  constructor(ui) {
    this.ui = ui;
  }

  init() {
    const copyPasteBtns = document.getElementById("reactor_copy_paste_btns");
    const toggleBtn = document.getElementById("reactor_copy_paste_toggle");
    const copyBtn = document.getElementById("reactor_copy_btn");
    const pasteBtn = document.getElementById("reactor_paste_btn");
    const deselectBtn = document.getElementById("reactor_deselect_btn");
    const dropperBtn = document.getElementById("reactor_dropper_btn");
    const getRefs = () => getCopyPasteRefs() ?? openCopyPasteDialogHost();

    if (toggleBtn && copyPasteBtns) {
      toggleBtn.onclick = () => {
        const uiState = this.ui.uiState;
        if (uiState) uiState.copy_paste_collapsed = !uiState.copy_paste_collapsed;
        else copyPasteBtns.classList.toggle("collapsed");
        if (copyPasteBtns) StorageUtils.set("reactor_copy_paste_collapsed", copyPasteBtns.classList.contains("collapsed"));
      };
    }

    this.setupBlueprintPlannerControls();

    if (!copyBtn || !pasteBtn) return;

    if (deselectBtn) {
      deselectBtn.onclick = () => {
        document.querySelectorAll(".part.part_active").forEach((el) => el.classList.remove("part_active"));
        this.ui.stateManager.setClickedPart(null);
      };
    }

    if (dropperBtn) {
      dropperBtn.onclick = () => {
        this.ui._dropperModeActive = !this.ui._dropperModeActive;
        dropperBtn.classList.toggle("on", this.ui._dropperModeActive);
      };
    }

    setupCopyAction(this.ui, { copyBtn, getRefs });
    setupPasteAction(this.ui, { pasteBtn, getRefs });
  }

  open(data) {
    if (typeof this.ui._showPasteModalWithData === "function") this.ui._showPasteModalWithData(data ?? "");
  }

  setupCopyStateButton() {
    const ui = this.ui;
    const copyStateBtn = document.getElementById("copy_state_btn");
    if (!copyStateBtn || !ui.uiState || !ui.game?.saveManager) return;
    copyStateBtn.onclick = async () => {
      try {
        const gameStateObject = await ui.game.saveManager.getSaveState();
        const gameStateString = serializeSave(gameStateObject);
        if (navigator.clipboard?.writeText) await navigator.clipboard.writeText(gameStateString);
        ui.uiState.copy_state_feedback = "Copied!";
      } catch (_) {
        ui.uiState.copy_state_feedback = "Error!";
      }
      setTimeout(() => {
        if (ui.uiState) ui.uiState.copy_state_feedback = null;
      }, 2000);
    };
  }

  pasteReactorLayout(layout, options = {}) {
    const ui = this.ui;
    if (!layout || !ui.game) return;
    queueBlueprintPaste(ui.game, layout, options);
    ui.game.engine?.consumeIntentQueueAsync?.().then(() => {
      ui.gridCanvasRenderer?.markStaticDirty?.();
      startRenderLoop(ui, 0);
    });
  }

  setupBlueprintPlannerControls() {
    const ui = this.ui;
    const game = ui.game;
    const toggle = document.getElementById("reactor_blueprint_toggle");
    const applyBtn = document.getElementById("blueprint_planner_apply");
    const partialBtn = document.getElementById("blueprint_planner_partial");
    const exportBtn = document.getElementById("blueprint_planner_export");
    const discardBtn = document.getElementById("blueprint_planner_discard");
    if (!toggle || !game) return;
    if (typeof this._teardownBlueprintPlanner === "function") this._teardownBlueprintPlanner();
    let blueprintHudTimer = null;
    const syncHud = () => {
      if (blueprintHudTimer) clearTimeout(blueprintHudTimer);
      blueprintHudTimer = setTimeout(async () => {
        blueprintHudTimer = null;
        const pEl = document.getElementById("blueprint_planner_power");
        const hEl = document.getElementById("blueprint_planner_net_heat");
        const epEl = document.getElementById("blueprint_planner_ep");
        const sEl = document.getElementById("blueprint_planner_stability");
        if (!game.blueprintPlanner?.active) {
          if (pEl) pEl.textContent = "";
          if (hEl) hEl.textContent = "";
          if (epEl) epEl.textContent = "";
          if (sEl) sEl.textContent = "";
          return;
        }
        let pwr = null;
        let net = null;
        let ep = null;
        if (typeof game.requestBlueprintProjectionSample === "function") {
          const res = await game.requestBlueprintProjectionSample();
          const sample = res?.projectionPlannerSample;
          if (sample && typeof sample.stats_power === "number") pwr = sample.stats_power;
          if (sample && typeof sample.stats_net_heat === "number") net = sample.stats_net_heat;
          if (sample && typeof sample.stats_ep === "number") ep = sample.stats_ep;
        }
        if (pEl) pEl.textContent = pwr != null ? `Pwr ${fmt(pwr ?? 0, 0)}/t` : "";
        if (hEl) hEl.textContent = net != null ? `\u0394Heat ${fmt(net ?? 0, 0)}/t` : "";
        if (epEl) epEl.textContent = ep != null && ep > 0 ? `EP ${fmt(ep, 2)}/t` : "";
        if (sEl) {
          if (net == null) sEl.textContent = "";
          else if (net < 0) sEl.textContent = "Stable";
          else if (net > 0) sEl.textContent = "Net heating";
          else sEl.textContent = "Balanced";
        }
        ui.gridCanvasRenderer?.markStaticDirty?.();
      }, 30);
    };
    const onChanged = () => {
      if (ui.uiState?.copy_paste_display) {
        ui.uiState.copy_paste_display.blueprintPlannerActive = !!game.blueprintPlanner?.active;
      }
      syncHud();
    };
    const onDeficit = (result) => showBlueprintDeficitToast(result);
    if (game.on) {
      game.on("blueprintApplyDeficit", onDeficit);
    }
    let blueprintUnsub = null;
    if (game.blueprintPlanner) {
      blueprintUnsub = subscribe(game.blueprintPlanner, onChanged);
    }
    this._teardownBlueprintPlanner = () => {
      if (blueprintHudTimer) clearTimeout(blueprintHudTimer);
      blueprintHudTimer = null;
      if (blueprintUnsub) {
        try { blueprintUnsub(); } catch (_) {}
        blueprintUnsub = null;
      }
      if (game.off) {
        game.off("blueprintApplyDeficit", onDeficit);
      }
      this._teardownBlueprintPlanner = null;
    };
    const syncPlanToggle = () => {
      const active = !!ui.uiState?.copy_paste_display?.blueprintPlannerActive;
      toggle.setAttribute("aria-pressed", String(active));
      toggle.title = active ? "Blueprint planning mode on" : "Live reactor mode";
    };
    toggle.onclick = () => {
      game.toggleBlueprintPlanner?.();
      syncHud();
      syncPlanToggle();
    };
    syncPlanToggle();
    const afterApply = () => {
      syncHud();
      startRenderLoop(ui, 0);
      ui.gridCanvasRenderer?.markStaticDirty?.();
    };
    if (applyBtn) {
      applyBtn.onclick = () => {
        game.applyBlueprintPlannerLayout?.().then(afterApply);
      };
    }
    if (partialBtn) {
      partialBtn.onclick = () => {
        game.applyBlueprintPlannerLayout?.({ partial: true }).then(afterApply);
      };
    }
    if (exportBtn) {
      exportBtn.onclick = async () => {
        const res = await game.requestBlueprintProjectionSample?.({ recordTicks: true });
        const series = res?.projectionPlannerSample?.tick_series;
        if (!series?.length) return;
        const stamp = new Date().toISOString().replace(/[:.]/g, "-");
        downloadTextFile(`blueprint-ticks-${stamp}.json`, JSON.stringify(series, null, 2), "application/json");
        downloadTextFile(`blueprint-ticks-${stamp}.csv`, tickSeriesToCsv(series), "text/csv");
      };
    }
    if (discardBtn) {
      discardBtn.onclick = () => {
        game.clearBlueprintPlannerSlots?.();
        syncHud();
      };
    }
    this.setupLayoutCompareControls();
  }

  setupLayoutCompareControls() {
    const ui = this.ui;
    const game = ui.game;
    const openBtn = document.getElementById("reactor_compare_layouts_btn");
    const modal = document.getElementById("layout_compare_modal");
    const closeBtn = document.getElementById("layout_compare_close_btn");
    const runBtn = document.getElementById("layout_compare_run_btn");
    const resultsEl = document.getElementById("layout_compare_results");
    if (!openBtn || !modal || !game) return;
    const hide = () => modal.classList.add("hidden");
    const show = () => modal.classList.remove("hidden");
    openBtn.onclick = show;
    if (closeBtn) closeBtn.onclick = hide;
    modal.onclick = (e) => { if (e.target === modal) hide(); };
    if (!runBtn || !resultsEl) return;
    runBtn.onclick = async () => {
      const aRaw = document.getElementById("layout_compare_a")?.value?.trim() ?? "";
      const bRaw = document.getElementById("layout_compare_b")?.value?.trim() ?? "";
      const layoutA = deserializeReactorInput(aRaw, game);
      const layoutB = deserializeReactorInput(bRaw, game);
      if (!layoutA || !layoutB) {
        resultsEl.textContent = "Invalid layout A or B.";
        return;
      }
      resultsEl.textContent = "Running steady-state sandbox…";
      const [resA, resB] = await Promise.all([
        game.requestLayoutProjectionSample?.(clipToGrid(layoutA, game.rows, game.cols)),
        game.requestLayoutProjectionSample?.(clipToGrid(layoutB, game.rows, game.cols)),
      ]);
      const sA = resA?.projectionPlannerSample;
      const sB = resB?.projectionPlannerSample;
      if (!sA || !sB) {
        resultsEl.textContent = "Sandbox unavailable (worker offline).";
        return;
      }
      const row = (label, key, digits = 0) => {
        const a = sA[key] ?? 0;
        const b = sB[key] ?? 0;
        const d = b - a;
        const sign = d > 0 ? "+" : "";
        return `${label}: A ${fmt(a, digits)} | B ${fmt(b, digits)} | Î” ${sign}${fmt(d, digits)}`;
      };
      resultsEl.innerHTML = [
        row("Power/tick", "stats_power"),
        row("Net heat/tick", "stats_net_heat"),
        row("EP/tick", "stats_ep", 2),
      ].join("<br>");
    };
  }

  teardownBlueprintPlanner() {
    if (typeof this._teardownBlueprintPlanner === "function") this._teardownBlueprintPlanner();
  }
}

export function hideCopyPasteModal(ui) {
  const root = document.getElementById("modal-root");
  const modal = root?.querySelector("#reactor_copy_paste_modal");
  const prevPauseState = modal?.dataset?.previousPauseState;
  modalUi.activeModal = null;
  modalUi.payload = null;
  if (root) {
    render(nothing, root);
    syncModalDialogOpen(root, false);
  }
  if (prevPauseState != null && ui?.game) {
    ui.game.onToggleStateChange?.("pause", prevPauseState === "true");
  }
}

import { getIndex } from "../simUtils.js";
import {
  GRID_TARGET_TOTAL_TILES,
  GRID_MIN_DIMENSION,
  GRID_MAX_DISPLAY_DIMENSION,
  ZOOM_DAMPING_FACTOR,
  PINCH_DISTANCE_THRESHOLD_PX,
  MOMENTUM_DECAY_FACTOR,
  SNAP_BACK_THRESHOLD_RATIO,
  SNAP_BACK_SPRING_CONSTANT,
  ZOOM_SCALE_MIN,
  ZOOM_SCALE_MAX,
  GRID,
} from "../constants/balance.js";
import {
  COLORS,
  OVERHEAT_VISUAL,
  BAR,
  HEAT_MAP,
  HEAT_SHIMMER,
  HEAT_HAZE,
  HEAT_FLOW,
} from "../constants/heat-visual.js";
import { MOBILE_BREAKPOINT_PX, MOBILE_MIN_TILE_PX, DESKTOP_MIN_TILE_PX, MAX_TILE_SIZE_PX } from "../constants/ui-constants.js";
import { logger } from "../core/logger.js";
import { vuSegmentRatio01 } from "../core/math-helpers.js";
import { BaseComponent, getDomElementById } from "../dom/lit.js";
import { actions } from "../store.js";
import { getPageReactor, getPageReactorWrapper } from "./page-dom.js";
import { subscribeKey } from "valtio/vanilla/utils";

export { Tileset } from "../logic.js";

const rendererSurfaces = new WeakMap();

export function bindGridRendererSurfaces(renderer, surfaces) {
  rendererSurfaces.set(renderer, surfaces);
}

class StaticGridRenderer {
  constructor(shared) {
    this._shared = shared;
  }

  drawTile(game, r, c) {
    const { ctx, _tileSize: ts } = this._shared;
    const x = c * ts;
    const y = r * ts;
    const tile = game.tileset?.getTile(r, c);
    const occupied = tile?.enabled && tile.part;
    ctx.fillStyle = COLORS.tileBg;
    ctx.strokeStyle = COLORS.tileStroke;
    ctx.lineWidth = 3;
    ctx.fillRect(x, y, ts, ts);
    if (!occupied) {
      ctx.strokeStyle = COLORS.tileMachinedLine;
      ctx.lineWidth = 1;
      ctx.beginPath();
      ctx.moveTo(x, y);
      ctx.lineTo(x + ts, y + ts);
      ctx.moveTo(x + ts, y);
      ctx.lineTo(x, y + ts);
      ctx.stroke();
    }
    ctx.strokeStyle = COLORS.tileStroke;
    ctx.lineWidth = 3;
    ctx.strokeRect(x + 1.5, y + 1.5, ts - 3, ts - 3);
    if (occupied) {
      const path = typeof tile.part.getImagePath === "function" ? tile.part.getImagePath() : null;
      if (path) {
        ctx.fillStyle = COLORS.tileOccDropShadow;
        ctx.fillRect(x + 1, y + 5, ts - 2, ts - 2);
        this._shared.drawPartSprite(ctx, path, x, y, ts);
      }
    }
    if (game.blueprintPlanner?.active && game.partset && typeof game.getBlueprintPlannerPartId === "function") {
      const ghostId = game.getBlueprintPlannerPartId(r, c);
      if (ghostId) {
        const ghostPart = game.partset.getPartById(ghostId);
        const gpath = ghostPart && typeof ghostPart.getImagePath === "function" ? ghostPart.getImagePath() : null;
        if (gpath) {
          ctx.save();
          ctx.globalAlpha = 0.5;
          this._shared.drawPartSprite(ctx, gpath, x, y, ts);
          ctx.restore();
          ctx.save();
          const liveId = occupied ? tile.part?.id : null;
          const isDiff = liveId !== ghostId;
          ctx.strokeStyle = isDiff ? "rgb(255 160 60)" : "rgb(0 200 255)";
          ctx.setLineDash([5, 4]);
          ctx.lineWidth = 2;
          ctx.strokeRect(x + 2, y + 2, ts - 4, ts - 4);
          ctx.setLineDash([]);
          ctx.restore();
        }
      }
    }
  }

  render(game, viewport) {
    const { ctx, _width, _height, _rows: rows, _cols: cols, _tileSize: ts, _staticDirty, _staticDirtyTiles } = this._shared;
    if (!ctx || _width <= 0 || _height <= 0) {
      if (!this._shared._staticBailLogged) {
        this._shared._staticBailLogged = true;
        logger.log("warn", "ui", "[StaticGrid] render bailed", { hasCtx: !!ctx, width: _width, height: _height });
      }
      return;
    }
    this._shared._staticBailLogged = false;
    const cull = viewport != null;

    if (_staticDirty) {
      ctx.clearRect(0, 0, _width, _height);
      Array.from({ length: rows }, (_, r) => r).forEach((r) =>
        Array.from({ length: cols }, (_, c) => c).forEach((c) => {
          if (!cull || this._shared.tileInViewport(r, c, viewport)) this.drawTile(game, r, c);
        })
      );
      this._shared._staticDirty = false;
      this._shared._staticDirtyTiles.clear();
      return;
    }

    if (_staticDirtyTiles.size === 0) return;
    _staticDirtyTiles.forEach((key) => {
      const [r, c] = key.split(",").map(Number);
      if (!cull || this._shared.tileInViewport(r, c, viewport)) {
        ctx.clearRect(c * ts, r * ts, ts, ts);
        this.drawTile(game, r, c);
      }
    });
    this._shared._staticDirtyTiles.clear();
  }
}

class DynamicOverlayRenderer {
  constructor(shared) {
    this._shared = shared;
  }

  render(game, viewport, ui) {
    const { _dynamicCtx: ctx, _width, _height, _tileSize: ts } = this._shared;
    if (!ctx || !game?.tileset || _width <= 0 || _height <= 0) return;

    const tiles = game.tileset.active_tiles_list;
    if (!tiles) return;
    const cull = viewport != null;
    const now = typeof performance !== "undefined" ? performance.now() : 0;
    const pulseAlpha = 0.12 + Math.sin(now * 0.002) * 0.06;

    for (let i = 0; i < tiles.length; i++) {
      const tile = tiles[i];
      if (!tile?.enabled || !tile.part) continue;
      const r = tile.row;
      const c = tile.col;
      if (cull && !this._shared.tileInViewport(r, c, viewport)) continue;
      const x = c * ts;
      const y = r * ts;

      if (tile.part?.category === "cell" && tile.ticks > 0) {
        const flick = Math.floor(now / 75) % 2;
        const a = 0.12 + flick * 0.28;
        ctx.save();
        ctx.globalCompositeOperation = "screen";
        ctx.fillStyle = `rgba(0, 242, 255, ${a})`;
        ctx.fillRect(x, y, ts, ts);
        ctx.restore();
      }

      const maxHeat = tile.part.containment || 1;
      const hasHeatBar = tile.part.base_containment > 0 || (tile.part.containment > 0 && tile.part.category !== "valve");
      const hasDurability = tile.part.base_ticks > 0;
      const barH = Math.max(BAR.minBarHeight, (ts * BAR.barHeightRatio) | 0);
      if (hasHeatBar && tile.heat_contained != null) {
        const pct = vuSegmentRatio01(Math.max(0, Math.min(1, tile.heat_contained / maxHeat)));
        const by = hasDurability ? y + 1 : y + ts - barH;
        ctx.fillStyle = COLORS.heatBarBg;
        ctx.fillRect(x, by, ts, barH);
        ctx.fillStyle = COLORS.heatBarFill;
        ctx.fillRect(x, by, ts * pct, barH);
      }

      if (hasDurability && tile.ticks != null && tile.part.ticks > 0) {
        const pct = vuSegmentRatio01(Math.max(0, Math.min(1, tile.ticks / tile.part.ticks)));
        const by = y + ts - barH;
        if (!hasHeatBar) {
          ctx.fillStyle = COLORS.heatBarBg;
          ctx.fillRect(x, by, ts, barH);
        }
        ctx.fillStyle = COLORS.durabilityBarFill;
        ctx.fillRect(x, by, ts * pct, barH);
      }

      if (hasHeatBar && tile.part.containment > 0) {
        const heatRatio = tile.heat_contained / tile.part.containment;
        if (heatRatio >= OVERHEAT_VISUAL.heatRatioThreshold) {
          const wiggle = Math.sin(now * OVERHEAT_VISUAL.wiggleFreq) * OVERHEAT_VISUAL.wiggleAmplitude;
          ctx.strokeStyle = `rgba(255, 80, 60, ${OVERHEAT_VISUAL.strokeBaseAlpha + Math.sin(now * OVERHEAT_VISUAL.strokePulseFreq) * OVERHEAT_VISUAL.strokePulseAmplitude})`;
          ctx.lineWidth = OVERHEAT_VISUAL.lineWidth;
          ctx.strokeRect(x + wiggle, y, ts - wiggle * 2, ts);
          ctx.strokeRect(x, y + wiggle, ts, ts - wiggle * 2);
        }
      }

      if (tile.exploding) {
        const explosionAlpha = 0.35 + Math.sin(now * 0.02) * 0.2;
        ctx.fillStyle = COLORS.explosionGlow(explosionAlpha);
        ctx.fillRect(x, y, ts, ts);
        ctx.strokeStyle = COLORS.explosionStroke(explosionAlpha);
        ctx.lineWidth = 3;
        ctx.strokeRect(x + 1, y + 1, ts - 2, ts - 2);
      }

      const sellingTile = ui?.getSellingTile?.();
      if (sellingTile === tile) {
        ctx.fillStyle = COLORS.sellingFill;
        ctx.fillRect(x, y, ts, ts);
        ctx.strokeStyle = COLORS.sellingStroke;
        ctx.lineWidth = 2;
        ctx.strokeRect(x, y, ts, ts);
      }
    }

    const highlightedTiles = ui?.getHighlightedTiles?.();
    if (highlightedTiles?.length) {
      ctx.fillStyle = COLORS.highlightFill;
      for (let i = 0; i < highlightedTiles.length; i++) {
        const t = highlightedTiles[i];
        if (!t?.enabled) continue;
        const r = t.row;
        const c = t.col;
        if (cull && !this._shared.tileInViewport(r, c, viewport)) continue;
        ctx.fillRect(c * ts, r * ts, ts, ts);
        ctx.strokeStyle = COLORS.highlightStroke;
        ctx.lineWidth = 2;
        ctx.strokeRect(c * ts, r * ts, ts, ts);
      }
    }

    const hoveredTile = ui?.getHoveredTile?.();
    if (hoveredTile?.enabled) {
      const r = hoveredTile.row;
      const c = hoveredTile.col;
      if (!cull || this._shared.tileInViewport(r, c, viewport)) {
        const x = c * ts;
        const y = r * ts;
        ctx.fillStyle = COLORS.hoverFill;
        ctx.fillRect(x, y, ts, ts);
        ctx.strokeStyle = COLORS.hoverStroke;
        ctx.lineWidth = 1.5;
        ctx.strokeRect(x, y, ts, ts);
      }
    }
  }
}

class HeatEffectsRenderer {
  constructor(shared) {
    this._shared = shared;
  }

  _smoothHeatMap(heatMap, rows, cols, gridIndex) {
    const out = new Float64Array(rows * cols);
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        let sum = 0;
        let n = 0;
        for (let dr = -1; dr <= 1; dr++) {
          for (let dc = -1; dc <= 1; dc++) {
            const nr = r + dr;
            const nc = c + dc;
            if (nr >= 0 && nr < rows && nc >= 0 && nc < cols) {
              sum += heatMap[gridIndex(nr, nc)] || 0;
              n++;
            }
          }
        }
        out[gridIndex(r, c)] = n > 0 ? sum / n : 0;
      }
    }
    return out;
  }

  _prepareHeatData(game) {
    const { _dynamicCtx, _width, _height, _rows: rows, _cols: cols } = this._shared;
    if (!_dynamicCtx || !game?.tileset?.heatMap || _width <= 0 || _height <= 0) return null;
    const gridIndex = (r, c) => getIndex(r, c, game.tileset.max_cols);
    const smoothed = this._smoothHeatMap(game.tileset.heatMap, rows, cols, gridIndex);
    let maxHeat = 0;
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        const h = smoothed[gridIndex(r, c)] || 0;
        if (h > maxHeat) maxHeat = h;
      }
    }
    if (maxHeat <= 0) return null;
    return { smoothed, maxHeat, gridIndex, rows, cols };
  }

  _drawHeatEffectsLayers(game, viewport) {
    const hd = this._prepareHeatData(game);
    if (!hd) return;
    const { smoothed, maxHeat, gridIndex, rows, cols } = hd;
    const ts = this._shared._tileSize;
    const now = typeof performance !== "undefined" ? performance.now() : 0;
    const cull = viewport != null && viewport.width > 0 && viewport.height > 0;
    const ctx = this._shared._dynamicCtx;
    const blobR = ts * HEAT_MAP.blobRadiusRatio;
    const sThresh = HEAT_SHIMMER.threshold;
    const hThresh = HEAT_HAZE.threshold;
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        if (cull && !this._shared.tileInViewport(r, c, viewport)) continue;
        const heat = smoothed[gridIndex(r, c)] || 0;
        const t = Math.max(0, Math.min(1, heat / maxHeat));
        if (t === 0) continue;
        const cx = c * ts + ts * 0.5;
        const cy = r * ts + ts * 0.5;
        ctx.fillStyle = `rgba(0,0,0,${HEAT_MAP.baseAlpha + HEAT_MAP.alphaRange * t})`;
        ctx.beginPath();
        ctx.ellipse(cx, cy, blobR, blobR, 0, 0, Math.PI * 2);
        ctx.fill();
        if (t >= sThresh) {
          const baseA = HEAT_SHIMMER.baseAlphaMultiplier * ((t - sThresh) / (1 - sThresh));
          for (let i = 0; i < HEAT_SHIMMER.layerCount; i++) {
            const phase = (now * HEAT_SHIMMER.timeScale + i * HEAT_SHIMMER.phaseSpacing) % (Math.PI * 2);
            const ox = Math.sin(phase) * (ts * 0.12);
            const oy = Math.cos(phase * 0.7) * (ts * 0.1);
            ctx.fillStyle = COLORS.shimmerTint(baseA * (0.6 + 0.4 * Math.sin(phase * 2)));
            ctx.beginPath();
            ctx.ellipse(
              cx + ox,
              cy + oy,
              ts * (0.35 + Math.sin(phase * 1.3) * 0.08),
              ts * (0.25 + Math.cos(phase * 0.9) * 0.06),
              phase * 0.3,
              0,
              Math.PI * 2
            );
            ctx.fill();
          }
        }
        if (t >= hThresh) {
          const rise = (now * HEAT_HAZE.riseSpeedPx) % (ts * 1.2);
          const hCy = cy - rise + Math.sin(now * HEAT_HAZE.wobbleFreq + r * 0.5 + c * 0.5) * ts * 0.15;
          const hCx = cx + Math.sin(now * 0.002 + c) * ts * 0.12;
          const rMax = ts * HEAT_HAZE.maxRadiusRatio;
          const grad = ctx.createRadialGradient(hCx, hCy, 0, hCx, hCy, rMax);
          const int = (t - hThresh) / (1 - hThresh);
          grad.addColorStop(0, `rgba(255, 220, 180, ${0.12 * int})`);
          grad.addColorStop(0.4, `rgba(255, 200, 150, ${0.06 * int})`);
          grad.addColorStop(1, "rgba(255, 200, 150, 0)");
          ctx.fillStyle = grad;
          ctx.beginPath();
          ctx.arc(cx, cy, rMax, 0, Math.PI * 2);
          ctx.fill();
        }
      }
    }
  }

  _drawHeatFlowLayer(game, viewport) {
    const engine = game?.engine;
    if (!this._shared._dynamicCtx || !engine || typeof engine.getLastHeatFlowVectors !== "function") return;
    const vectors = engine.getLastHeatFlowVectors();
    if (!vectors.length) return;
    const ts = this._shared._tileSize;
    const cull = viewport != null;
    const now = typeof performance !== "undefined" ? performance.now() : 0;
    const headLen = Math.max(4, Math.min(12, (ts * 10) / 48 | 0));
    const strokeWidth = Math.max(1.5, (ts * 2) / 48);
    const maxAmountForSpeed = HEAT_FLOW.maxAmountForSpeed;
    const dashLen = Math.max(6, (ts * 0.35) | 0);
    const gapLen = Math.max(4, (ts * 0.2) | 0);
    const ctx = this._shared._dynamicCtx;

    for (let i = 0; i < vectors.length; i++) {
      const v = vectors[i];
      if (cull) {
        const fromIn = this._shared.tileInViewport(v.fromRow, v.fromCol, viewport);
        const toIn = this._shared.tileInViewport(v.toRow, v.toCol, viewport);
        if (!fromIn && !toIn) continue;
      }
      const fromX = (v.fromCol + 0.5) * ts;
      const fromY = (v.fromRow + 0.5) * ts;
      const toX = (v.toCol + 0.5) * ts;
      const toY = (v.toRow + 0.5) * ts;
      const dx = toX - fromX;
      const dy = toY - fromY;
      const len = Math.hypot(dx, dy);
      if (len < 2) continue;
      const ux = dx / len;
      const uy = dy / len;
      const endX = toX - ux * headLen;
      const endY = toY - uy * headLen;
      const amount = typeof v.amount === "number" ? v.amount : 0;
      const speed = HEAT_FLOW.baseSpeed + (amount / maxAmountForSpeed) * HEAT_FLOW.speedAmountScale;
      const segLen = len - headLen;

      ctx.strokeStyle = COLORS.heatFlowArrow;
      ctx.lineWidth = strokeWidth;
      ctx.lineCap = "round";
      ctx.setLineDash([dashLen, gapLen]);
      const period = dashLen + gapLen;
      ctx.lineDashOffset = -(now * 0.001 * speed * period * 0.5) % period;
      ctx.beginPath();
      ctx.moveTo(fromX, fromY);
      ctx.lineTo(endX, endY);
      ctx.stroke();
      ctx.setLineDash([]);

      const ax = ux * headLen;
      const ay = uy * headLen;
      const perp = Math.max(2, headLen * 0.4);
      const px = -uy * perp;
      const py = ux * perp;
      ctx.fillStyle = COLORS.heatFlowArrowHead;
      ctx.beginPath();
      ctx.moveTo(toX, toY);
      ctx.lineTo(toX - ax + px, toY - ay + py);
      ctx.lineTo(toX - ax - px, toY - ay - py);
      ctx.closePath();
      ctx.fill();

      if (segLen > 4) {
        const pulseLen = HEAT_FLOW.pulseLen;
        const numPulses = HEAT_FLOW.pulseCount;
        for (let k = 0; k < numPulses; k++) {
          const phase = (now * 0.001 * speed + k / numPulses) % 1;
          const p0 = (phase - pulseLen * 0.5 + 1) % 1;
          const p1 = (phase + pulseLen * 0.5 + 1) % 1;
          const x0 = fromX + ux * segLen * p0;
          const y0 = fromY + uy * segLen * p0;
          const x1 = fromX + ux * segLen * p1;
          const y1 = fromY + uy * segLen * p1;
          const alpha = 0.5 + (amount / maxAmountForSpeed) * 0.45;
          ctx.strokeStyle = HEAT_FLOW.pulseColor(alpha);
          ctx.lineWidth = strokeWidth * 1.4;
          ctx.beginPath();
          ctx.moveTo(x0, y0);
          ctx.lineTo(x1, y1);
          ctx.stroke();
        }
      }
    }
  }

  render(game, viewport, ui) {
    if (ui?.getHeatMapVisible?.()) {
      this._drawHeatEffectsLayers(game, viewport);
    }
    if (ui?.getHeatFlowVisible?.() || ui?.getDebugOverlayVisible?.()) {
      this._drawHeatFlowLayer(game, viewport);
    }
  }
}

export class GridCanvasRenderer {
  constructor(ui) {
    this.ui = ui;
    this._width = 0;
    this._height = 0;
    this._rows = GRID.defaultRows;
    this._cols = GRID.defaultCols;
    this._tileSize = GRID.defaultTileSize;
    this._imageCache = new Map();
    this._imageCacheOrder = [];
    this._imageCacheMax = GRID.imageCacheMax;
    this._container = null;
    this._containerId = null;
    this._staticDirty = true;
    this._staticDirtyTiles = new Set();
    this._lastResizeRequest = 0;

    this._staticRenderer = new StaticGridRenderer(this);
    this._dynamicRenderer = new DynamicOverlayRenderer(this);
    this._heatRenderer = new HeatEffectsRenderer(this);
  }

  get canvas() {
    return rendererSurfaces.get(this)?.canvas ?? null;
  }

  get ctx() {
    return rendererSurfaces.get(this)?.ctx ?? null;
  }

  get _dynamicCanvas() {
    return rendererSurfaces.get(this)?.dynamicCanvas ?? null;
  }

  get _dynamicCtx() {
    return rendererSurfaces.get(this)?.dynamicCtx ?? null;
  }

  drawPartSprite(ctx, imagePath, dx, dy, ts) {
    const img = this.loadImage(imagePath);
    if (img.complete && img.naturalWidth) ctx.drawImage(img, dx, dy - 3, ts, ts);
  }

  loadImage(path) {
    if (this._imageCache.has(path)) return this._imageCache.get(path);
    while (this._imageCache.size >= this._imageCacheMax && this._imageCacheOrder.length) {
      const oldest = this._imageCacheOrder.shift();
      this._imageCache.delete(oldest);
    }
    const img = new Image();
    img.onload = () => this.markStaticDirty();
    img.src = path;
    this._imageCache.set(path, img);
    this._imageCacheOrder.push(path);
    while (this._imageCache.size > this._imageCacheMax && this._imageCacheOrder.length) {
      const oldest = this._imageCacheOrder.shift();
      this._imageCache.delete(oldest);
    }
    return img;
  }

  tileInViewport(row, col, viewport) {
    if (!viewport || viewport.width <= 0 || viewport.height <= 0) return true;
    const ts = this._tileSize;
    const left = col * ts;
    const top = row * ts;
    return left < viewport.left + viewport.width && left + ts > viewport.left &&
      top < viewport.top + viewport.height && top + ts > viewport.top;
  }

  init(containerElement) {
    if (!containerElement) {
      logger.log('warn', 'ui', '[Grid] init skipped: no container element');
      return;
    }
    const wrapper = document.createElement("div");
    wrapper.className = "reactor-canvas-host";
    wrapper.style.position = "relative";
    wrapper.style.width = "100%";
    wrapper.style.height = "100%";
    wrapper.style.minWidth = "0";
    wrapper.style.minHeight = "0";
    const canvas = document.createElement("canvas");
    canvas.style.display = "block";
    canvas.style.width = "100%";
    canvas.style.height = "100%";
    canvas.style.pointerEvents = "auto";
    const dynamicCanvas = document.createElement("canvas");
    dynamicCanvas.style.position = "absolute";
    dynamicCanvas.style.left = "0";
    dynamicCanvas.style.top = "0";
    dynamicCanvas.style.width = "100%";
    dynamicCanvas.style.height = "100%";
    dynamicCanvas.style.pointerEvents = "none";
    wrapper.appendChild(canvas);
    wrapper.appendChild(dynamicCanvas);
    containerElement.appendChild(wrapper);
    const ctx = canvas.getContext("2d");
    const dynamicCtx = dynamicCanvas.getContext("2d");
    rendererSurfaces.set(this, { canvas, dynamicCanvas, ctx, dynamicCtx });
    logger.log('debug', 'ui', '[Grid] init done, canvas attached to container');
    return canvas;
  }

  setSize(widthPx, heightPx) {
    const prevW = this._width;
    const prevH = this._height;
    this._width = Math.max(1, widthPx | 0);
    this._height = Math.max(1, heightPx | 0);
    if (prevW !== this._width || prevH !== this._height) {
      logger.log('debug', 'ui', `[Grid] setSize ${this._width}x${this._height}`);
    }
    const canvas = this.canvas;
    if (canvas) {
      canvas.width = this._width;
      canvas.height = this._height;
    }
    const dynamicCanvas = this._dynamicCanvas;
    if (dynamicCanvas) {
      dynamicCanvas.width = this._width;
      dynamicCanvas.height = this._height;
    }
  }

  setGridDimensions(rows, cols) {
    const newRows = Math.max(1, rows | 0);
    const newCols = Math.max(1, cols | 0);
    if (this._rows !== newRows || this._cols !== newCols) {
      this.clearImageCache();
    }
    this._rows = newRows;
    this._cols = newCols;
    this._tileSize = Math.min(
      this._width / this._cols,
      this._height / this._rows
    ) | 0;
  }

  setContainer(containerElement) {
    this._containerId = containerElement?.id || null;
    this._container = null;
  }

  markStaticDirty() {
    this._staticDirty = true;
    this._staticDirtyTiles.clear();
  }

  markTileDirty(row, col) {
    if (this._staticDirty) return;
    this._staticDirtyTiles.add(`${row},${col}`);
  }

  clearImageCache() {
    this._imageCache.clear();
    this._imageCacheOrder.length = 0;
  }

  getCanvas() { return this.canvas; }
  getTileSize() { return this._tileSize; }
  getRows() { return this._rows; }
  getCols() { return this._cols; }

  hitTest(clientX, clientY) {
    if (!this.canvas || !this.ui?.game?.tileset) return null;
    const rect = this.canvas.getBoundingClientRect();
    const x = clientX - rect.left;
    const y = clientY - rect.top;
    const cols = Math.max(1, this._cols);
    const rows = Math.max(1, this._rows);
    const tileW = rect.width / cols;
    const tileH = rect.height / rows;
    const col = (x / tileW) | 0;
    const row = (y / tileH) | 0;
    if (row < 0 || row >= this._rows || col < 0 || col >= this._cols) return null;
    return this.ui.game.tileset.getTile(row, col);
  }

  getTileRectInContainer(row, col, containerRect) {
    if (!this.canvas || !containerRect) return { left: 0, top: 0, width: 0, height: 0 };
    const reactorRect = this.canvas.getBoundingClientRect();
    const cols = Math.max(1, this._cols);
    const rows = Math.max(1, this._rows);
    const tw = reactorRect.width / cols;
    const th = reactorRect.height / rows;
    const left = reactorRect.left - containerRect.left + col * tw;
    const top = reactorRect.top - containerRect.top + row * th;
    return {
      left,
      top,
      width: tw,
      height: th,
      centerX: left + tw / 2,
      centerY: top + th / 2,
    };
  }

  _getViewport() {
    const el = getDomElementById(this._containerId);
    if (!el) return null;
    return {
      left: el.scrollLeft || 0,
      top: el.scrollTop || 0,
      width: el.clientWidth ?? 0,
      height: el.clientHeight ?? 0,
    };
  }

  render(game) {
    if (!game?.tileset) {
      if (!this._renderBailLogged) {
        this._renderBailLogged = true;
        logger.log('warn', 'ui', '[Grid] render bailed: no game.tileset');
      }
      return;
    }
    if (this._width <= 0 || this._height <= 0) {
      const wrapperExists = typeof document !== "undefined" && document.getElementById("reactor_wrapper");
      if (wrapperExists) {
        const now = typeof performance !== "undefined" ? performance.now() : Date.now();
        if (now - this._lastResizeRequest > 100) {
          this._lastResizeRequest = now;
          logger.log('warn', 'ui', `[Grid] render bailed: zero dimensions ${this._width}x${this._height}, requesting resize`);
          this.ui?.gridScaler?.requestResize?.();
        }
      }
      return;
    }
    this._renderBailLogged = false;
    const viewport = this._getViewport();

    if (this.ctx && (this._staticDirty || this._staticDirtyTiles.size > 0)) {
      this._staticRenderer.render(game, viewport);
    }

    if (this._dynamicCtx) {
      this._dynamicCtx.save();
      this._dynamicCtx.clearRect(0, 0, this._width, this._height);
      this._dynamicRenderer.render(game, viewport, this.ui);
      this._heatRenderer.render(game, viewport, this.ui);
      this._dynamicCtx.restore();
    }
  }
}

export class GridScaler extends BaseComponent {

    constructor(ui) {
        super();
        this.ui = ui;
        this.wrapper = null;
        this.reactor = null;
        this.resizeObserver = null;
        this._lastResizeSig = undefined;
        this._reseatTimeoutId = null;

        this.config = {
            targetTotalTiles: GRID_TARGET_TOTAL_TILES,
            minCols: GRID_MIN_DIMENSION,
            minRows: GRID_MIN_DIMENSION,
            maxCols: GRID_MAX_DISPLAY_DIMENSION,
            maxRows: GRID_MAX_DISPLAY_DIMENSION
        };

        this.gestureState = {
            isPinching: false,
            isPanning: false,
            initialDistance: 0,
            initialScale: 1,
            initialTranslate: { x: 0, y: 0 },
            pinchMidpointInWrapper: { x: 0, y: 0 },
            currentTranslate: { x: 0, y: 0 },
            currentScale: 1,
            targetTranslate: { x: 0, y: 0 },
            targetScale: 1,
            zoomDamping: ZOOM_DAMPING_FACTOR,
            touches: [],
            pinchDistanceThreshold: PINCH_DISTANCE_THRESHOLD_PX,
            lastTranslate: { x: 0, y: 0 },
            lastMoveTime: 0,
            velocity: { x: 0, y: 0 },
            momentumDecay: MOMENTUM_DECAY_FACTOR,
            snapBackThreshold: SNAP_BACK_THRESHOLD_RATIO,
            snapBackSpring: SNAP_BACK_SPRING_CONSTANT,
            _animationId: null
        };

    }



    init() {

        this.reactor = getPageReactor(this.ui) ?? document.getElementById("reactor");
        this.wrapper = getPageReactorWrapper(this.ui) ?? document.getElementById("reactor_wrapper");

        if (!this.wrapper) return;

        this.resizeObserver = new ResizeObserver(() => this.requestResize());
        this.resizeObserver.observe(this.wrapper);

        this.requestResize();

        const isMobile = typeof window !== 'undefined' && window.innerWidth <= GridScaler.MOBILE_BREAKPOINT_PX;
        if (isMobile) {
            this.setupGestures();
        }

    }

    teardown() {
        if (this.resizeObserver && this.wrapper) {
            this.resizeObserver.disconnect();
            this.resizeObserver = null;
        }
        if (this._touchHandlers && this.wrapper) {
            this.wrapper.removeEventListener('touchstart', this._touchHandlers.start);
            this.wrapper.removeEventListener('touchmove', this._touchHandlers.move);
            this.wrapper.removeEventListener('touchend', this._touchHandlers.end);
            this.wrapper.removeEventListener('touchcancel', this._touchHandlers.end);
            this._touchHandlers = null;
        }
    }

    setupGestures() {
        if (!this.wrapper) return;

        this._touchHandlers = {
            start: (e) => this.handleTouchStart(e),
            move: (e) => this.handleTouchMove(e),
            end: (e) => this.handleTouchEnd(e),
        };
        this.wrapper.addEventListener('touchstart', this._touchHandlers.start, { passive: false });
        this.wrapper.addEventListener('touchmove', this._touchHandlers.move, { passive: false });
        this.wrapper.addEventListener('touchend', this._touchHandlers.end, { passive: false });
        this.wrapper.addEventListener('touchcancel', this._touchHandlers.end, { passive: false });
    }

    getDistance(touch1, touch2) {
        const dx = touch2.clientX - touch1.clientX;
        const dy = touch2.clientY - touch1.clientY;
        return Math.sqrt(dx * dx + dy * dy);
    }

    getMidpoint(touch1, touch2) {
        return {
            x: (touch1.clientX + touch2.clientX) / 2,
            y: (touch1.clientY + touch2.clientY) / 2
        };
    }

    handleTouchStart(e) {
        if (e.touches.length === 2) {
            this.gestureState.touches = Array.from(e.touches);
            this.gestureState.initialDistance = this.getDistance(e.touches[0], e.touches[1]);
            this.gestureState.initialScale = this.gestureState.currentScale || 1;
            this.gestureState.initialTranslate = { ...this.gestureState.currentTranslate };
            this.gestureState.targetScale = this.gestureState.currentScale;
            this.gestureState.targetTranslate = { ...this.gestureState.currentTranslate };
            const midpoint = this.getMidpoint(e.touches[0], e.touches[1]);
            const wrapperRect = this.wrapper.getBoundingClientRect();
            const wrapperCenterX = wrapperRect.left + wrapperRect.width / 2;
            const wrapperCenterY = wrapperRect.top + wrapperRect.height / 2;
            this.gestureState.pinchMidpointInWrapper = {
                x: midpoint.x - wrapperCenterX,
                y: midpoint.y - wrapperCenterY
            };
            this.gestureState.isPinching = false;
            this.gestureState.isPanning = false;
            this.gestureState.lastMoveTime = performance.now();
            this.gestureState.lastTranslate = { ...this.gestureState.currentTranslate };
        } else if (e.touches.length === 1) {
            this.gestureState.isPinching = false;
            this.gestureState.isPanning = false;
            this.gestureState.touches = [];
        }
    }

    handleTouchMove(e) {
        if (e.touches.length !== 2) return;
        const currentDistance = this.getDistance(e.touches[0], e.touches[1]);
        if (!this.gestureState.isPinching && !this.gestureState.isPanning) {
            const threshold = this.gestureState.pinchDistanceThreshold || 10;
            const distanceDelta = Math.abs(currentDistance - this.gestureState.initialDistance);
            if (distanceDelta < threshold) return;
            this.gestureState.isPinching = true;
            this.gestureState.isPanning = true;
        }
        e.preventDefault();
        const g = this.gestureState;
        const now = performance.now();
        const dt = Math.min(100, now - g.lastMoveTime) / 1000;
        if (dt > 0) {
            g.velocity.x = (g.currentTranslate.x - g.lastTranslate.x) / dt;
            g.velocity.y = (g.currentTranslate.y - g.lastTranslate.y) / dt;
        }
        g.lastTranslate = { ...g.currentTranslate };
        g.lastMoveTime = now;

        const d = g.zoomDamping;
        const scale = (currentDistance / g.initialDistance) * g.initialScale;
        const clampedScale = Math.max(ZOOM_SCALE_MIN, Math.min(ZOOM_SCALE_MAX, scale));
        g.targetScale = clampedScale;
        const ratio = g.currentScale > 0 ? clampedScale / g.currentScale : 1;
        const mx = g.pinchMidpointInWrapper.x;
        const my = g.pinchMidpointInWrapper.y;
        g.targetTranslate = {
            x: g.currentTranslate.x * ratio + mx * (1 - ratio),
            y: g.currentTranslate.y * ratio + my * (1 - ratio)
        };
        const currentMidpoint = this.getMidpoint(e.touches[0], e.touches[1]);
        const previousMidpoint = this.getMidpoint(g.touches[0], g.touches[1]);
        g.targetTranslate.x += currentMidpoint.x - previousMidpoint.x;
        g.targetTranslate.y += currentMidpoint.y - previousMidpoint.y;

        g.currentScale += (g.targetScale - g.currentScale) * d;
        g.currentTranslate.x += (g.targetTranslate.x - g.currentTranslate.x) * d;
        g.currentTranslate.y += (g.targetTranslate.y - g.currentTranslate.y) * d;
        g.touches = Array.from(e.touches);
        this.applyTransform();
    }

    handleTouchEnd(e) {
        if (e.touches.length < 2) {
            this.gestureState.isPinching = false;
            this.gestureState.isPanning = false;
            this.gestureState.touches = [];
            this.startInertiaOrSnapBack();
        }
    }

    startInertiaOrSnapBack() {
        if (this.gestureState._animationId) cancelAnimationFrame(this.gestureState._animationId);
        const g = this.gestureState;
        const run = () => {
            const w = this.wrapper;
            if (!w || !this.reactor) return;
            const wW = w.clientWidth || 1;
            const wH = w.clientHeight || 1;
            const limitX = wW * g.snapBackThreshold;
            const limitY = wH * g.snapBackThreshold;
            const needSnap = Math.abs(g.currentTranslate.x) > limitX || Math.abs(g.currentTranslate.y) > limitY;
            const speed = Math.sqrt(g.velocity.x * g.velocity.x + g.velocity.y * g.velocity.y);
            const stillMoving = speed > 5;

            if (stillMoving && !needSnap) {
                g.currentTranslate.x += g.velocity.x * 0.016;
                g.currentTranslate.y += g.velocity.y * 0.016;
                g.velocity.x *= g.momentumDecay;
                g.velocity.y *= g.momentumDecay;
            } else if (needSnap) {
                g.velocity.x = 0;
                g.velocity.y = 0;
                g.currentTranslate.x += (0 - g.currentTranslate.x) * g.snapBackSpring;
                g.currentTranslate.y += (0 - g.currentTranslate.y) * g.snapBackSpring;
            } else {
                g.velocity.x = 0;
                g.velocity.y = 0;
            }

            this.applyTransform();
            const stillSnapping = needSnap && (Math.abs(g.currentTranslate.x) > 1 || Math.abs(g.currentTranslate.y) > 1);
            if (stillMoving || stillSnapping) {
                g._animationId = requestAnimationFrame(run);
            } else {
                g._animationId = null;
            }
        };
        g._animationId = requestAnimationFrame(run);
    }

    applyTransform() {
        if (!this.reactor) return;

        const { currentScale, currentTranslate } = this.gestureState;
        const transform = `translate(${currentTranslate.x}px, ${currentTranslate.y}px) scale(${currentScale})`;
        this.reactor.style.transform = transform;
        this.reactor.style.transformOrigin = 'center center';
    }

    resetTransform() {
        if (!this.reactor) return;

        this.gestureState.currentScale = 1;
        this.gestureState.targetScale = 1;
        this.gestureState.currentTranslate = { x: 0, y: 0 };
        this.gestureState.targetTranslate = { x: 0, y: 0 };
        this.reactor.style.transform = '';
        this.reactor.style.transformOrigin = '';
    }



    requestResize() {
        if (this.ui?.game) {
            requestAnimationFrame(() => this.resize());
        }
    }


    static get MOBILE_BREAKPOINT_PX() { return MOBILE_BREAKPOINT_PX; }
    static get MOBILE_MIN_TILE_PX() { return MOBILE_MIN_TILE_PX; }
    static get DESKTOP_MIN_TILE_PX() { return DESKTOP_MIN_TILE_PX; }
    static get MAX_TILE_SIZE_PX() { return MAX_TILE_SIZE_PX; }
    static get MOBILE_PREF_COLS() { return 8; }
    static get MOBILE_TALL_ROWS() { return 14; }
    static get MOBILE_MED_ROWS() { return 10; }
    static get MAX_DESKTOP_COLS() { return 16; }

    getMobileGridDimensions(availWidth, availHeight) {
        const minTileSize = GridScaler.MOBILE_MIN_TILE_PX;
        const maxTilesX = Math.floor(availWidth / minTileSize);
        const maxTilesY = Math.floor(availHeight / minTileSize);
        let cols = GridScaler.MOBILE_PREF_COLS;
        cols = Math.max(this.config.minCols, Math.min(cols, maxTilesX, this.config.maxCols));
        let rows = maxTilesY >= GridScaler.MOBILE_TALL_ROWS ? GridScaler.MOBILE_TALL_ROWS : maxTilesY >= GridScaler.MOBILE_MED_ROWS ? GridScaler.MOBILE_MED_ROWS : Math.max(this.config.minRows, Math.min(maxTilesY, this.config.maxRows));
        const actualTileSizeY = availHeight / rows;
        if (actualTileSizeY < minTileSize) {
            rows = Math.floor(availHeight / minTileSize);
            rows = Math.max(this.config.minRows, Math.min(rows, this.config.maxRows));
        }
        return { rows, cols };
    }

    getDesktopGridDimensions(availWidth, availHeight) {
        const maxDesktopCols = GridScaler.MAX_DESKTOP_COLS;
        const minTileSize = GridScaler.DESKTOP_MIN_TILE_PX;
        const targetTotalTiles = this.config.targetTotalTiles;
        const maxTilesX = Math.floor(availWidth / minTileSize);
        const maxTilesY = Math.floor(availHeight / minTileSize);
        const idealCols = Math.ceil(Math.sqrt(targetTotalTiles));
        const cols = Math.min(maxTilesX, maxDesktopCols, Math.max(idealCols, this.config.minCols));
        let rows = Math.round(targetTotalTiles / cols);
        rows = Math.max(this.config.minRows, Math.min(rows, maxTilesY, this.config.maxRows));
        return { rows, cols };
    }

    calculateGridDimensions(availWidth, availHeight, maxTileSize) {
        const isMobile = typeof window !== 'undefined' && window.innerWidth <= GridScaler.MOBILE_BREAKPOINT_PX;
        if (isMobile) return this.getMobileGridDimensions(availWidth, availHeight);
        return this.getDesktopGridDimensions(availWidth, availHeight);
    }



    resize(_layoutRetry) {
        this.reactor = getPageReactor(this.ui) ?? document.getElementById("reactor");
        this.wrapper = getPageReactorWrapper(this.ui) ?? document.getElementById("reactor_wrapper");

        if (!this.reactor || !this.wrapper) {
            if (!this._resizeBailLogged && this.ui?.game) {
                this._resizeBailLogged = true;
                logger.log('debug', 'ui', '[GridScaler] resize skipped: reactor/wrapper not in DOM yet');
            }
            return;
        }
        this._resizeBailLogged = false;

        const availWidth = this.wrapper.clientWidth;
        const availHeight = this.wrapper.clientHeight;

        if (availWidth <= 0 || availHeight <= 0) {
            const retry = (_layoutRetry | 0) + 1;
            if (retry <= 4) {
                requestAnimationFrame(() => this.resize(retry));
            } else if (retry === 5 && this.ui?.game) {
                setTimeout(() => this.resize(5), 200);
            } else if (!this._layoutExhaustedLogged) {
                this._layoutExhaustedLogged = true;
                logger.log('debug', 'ui', '[GridScaler] zero dimensions after retries, will retry on next resize trigger');
            }
            return;
        }
        this._layoutExhaustedLogged = false;

        const maxTileSize = GridScaler.MAX_TILE_SIZE_PX;
        const isMobile = typeof window !== 'undefined' && window.innerWidth <= GridScaler.MOBILE_BREAKPOINT_PX;
        const dims = this.calculateGridDimensions(availWidth, availHeight, maxTileSize);

        let cols = dims.cols;
        let rows = dims.rows;

        const sizeXFinal = availWidth / cols;
        const sizeYFinal = availHeight / rows;
        let tileSize = Math.floor(Math.min(sizeXFinal, sizeYFinal, maxTileSize));
        
        const calculatedGridHeight = rows * tileSize;
        if (calculatedGridHeight > availHeight && isMobile) {
            const maxRowsForHeight = Math.floor(availHeight / tileSize);
            if (maxRowsForHeight >= this.config.minRows) {
                rows = maxRowsForHeight;
                tileSize = Math.floor(availHeight / rows);
            }
        }

        if (!this.ui?.game) {
            logger.log('warn', 'ui', '[GridScaler] resize bailed: no game instance');
            return;
        }
        if (this.ui.game.resizeGrid) {
            this.ui.game.resizeGrid(rows, cols);
        } else {
            this.ui.game.rows = rows;
            this.ui.game.cols = cols;
        }

        const finalGridWidth = cols * tileSize;
        const finalGridHeight = rows * tileSize;

        if (this.ui?.uiState) {
          this.ui.uiState.grid_layout = { cols, rows, tile_size_px: tileSize };
          const useCssGrid = this.ui.uiState.layout_css_grid === true;
          if (useCssGrid) {
            this.ui.uiState.grid_shell_width = 0;
            this.ui.uiState.grid_shell_height = 0;
          } else {
            this.ui.uiState.grid_shell_width = finalGridWidth;
            this.ui.uiState.grid_shell_height = finalGridHeight;
          }
        }

        const useCssGrid = this.ui?.uiState?.layout_css_grid === true;
        if (useCssGrid) {
            const hostW = this.reactor?.clientWidth ?? this.wrapper?.clientWidth ?? finalGridWidth;
            const hostH = this.reactor?.clientHeight ?? this.wrapper?.clientHeight ?? finalGridHeight;
            if (this.ui.gridCanvasRenderer) {
                this.ui.gridCanvasRenderer.setSize(hostW, hostH);
                this.ui.gridCanvasRenderer.setGridDimensions(rows, cols);
                this.ui.gridCanvasRenderer.markStaticDirty();
            }
        } else {
            if (this.ui.gridCanvasRenderer) {
                this.ui.gridCanvasRenderer.setSize(finalGridWidth, finalGridHeight);
                this.ui.gridCanvasRenderer.setGridDimensions(rows, cols);
                this.ui.gridCanvasRenderer.markStaticDirty();
                logger.log('debug', 'ui', `[GridScaler] resize complete: ${cols}x${rows} grid, ${finalGridWidth}x${finalGridHeight}px`);
            } else {
                logger.log('warn', 'ui', '[GridScaler] resize complete but gridCanvasRenderer missing');
            }
        }

        const sig = `${rows}|${cols}|${tileSize}`;
        const layoutChanged = this._lastResizeSig !== undefined && this._lastResizeSig !== sig;
        this._lastResizeSig = sig;
        if (layoutChanged) {
            this.reactor.style.filter = "brightness(2) contrast(2)";
            this.ui.deviceFeatures?.heavyVibration?.();
            if (this._reseatTimeoutId != null) clearTimeout(this._reseatTimeoutId);
            this._reseatTimeoutId = setTimeout(() => {
                this._reseatTimeoutId = null;
                if (this.reactor) this.reactor.style.filter = "";
                if (this.ui.game) actions.enqueueEffect(this.ui.game, { kind: "sfx", id: "reboot", vol: 0.5, context: "global" });
            }, 150);
        }

        this.applyWrapperAndSectionStyles(isMobile);
        applyReactorGridLayoutStyles(this.ui);
    }

    applyWrapperAndSectionStyles(isMobile) {
        if (!this.wrapper) return;
        this.wrapper.style.display = 'flex';
        this.wrapper.style.alignItems = 'center';
        this.wrapper.style.justifyContent = 'center';
        const section = document.getElementById('reactor_section') || this.wrapper.parentElement;
        if (section && isMobile) {
            const topBar = document.getElementById('mobile_passive_top_bar');
            const topOffset = topBar ? topBar.offsetHeight : 0;
            const buildRow = document.getElementById('build_above_deck_row');
            const controlDeck = document.getElementById('reactor_control_deck');
            const bottomNav = document.getElementById('bottom_nav');
            const bottomOffset = (buildRow?.offsetHeight || 0) + (controlDeck?.offsetHeight || 0) + (bottomNav?.offsetHeight || 0);
            section.style.paddingTop = `${topOffset}px`;
            section.style.paddingRight = '5px';
            section.style.paddingBottom = `${bottomOffset}px`;
            section.style.paddingLeft = '5px';
        }
        if (section && !isMobile) {
            section.style.paddingTop = '';
            section.style.paddingRight = '';
            section.style.paddingBottom = '';
            section.style.paddingLeft = '';
        }
        this.wrapper.style.paddingTop = '';
        this.wrapper.style.paddingRight = '';
        this.wrapper.style.paddingBottom = '';
        this.wrapper.style.paddingLeft = '';
    }

}

function buildReactorGridStyle(ui) {
  const gl = ui.uiState?.grid_layout ?? {};
  const useCssGrid = ui.uiState?.layout_css_grid === true;
  const style = {
    "--tile-size": gl.tile_size_px ? `${gl.tile_size_px}px` : undefined,
    "--game-cols": gl.cols ? String(gl.cols) : undefined,
    "--game-rows": gl.rows ? String(gl.rows) : undefined,
  };
  if (!useCssGrid) {
    if (ui.uiState?.grid_shell_width) style.width = `${ui.uiState.grid_shell_width}px`;
    if (ui.uiState?.grid_shell_height) style.height = `${ui.uiState.grid_shell_height}px`;
  }
  return style;
}

export function applyReactorGridLayoutStyles(ui) {
  const reactor = getPageReactor(ui);
  if (!reactor || !ui?.uiState) return;
  const useCssGrid = ui.uiState.layout_css_grid === true;
  reactor.classList.toggle("reactor-css-grid", useCssGrid);
  const mapped = buildReactorGridStyle(ui);
  for (const key of Object.keys(mapped)) {
    const val = mapped[key];
    if (val != null && val !== "") reactor.style.setProperty(key, val);
    else reactor.style.removeProperty(key);
  }
  if (useCssGrid) {
    reactor.style.removeProperty("width");
    reactor.style.removeProperty("height");
  }
}

export function mountReactorGridLayoutBinding(ui) {
  if (!ui?.uiState || ui._reactorGridLayoutUnsubs) return;
  const apply = () => applyReactorGridLayoutStyles(ui);
  ui._reactorGridLayoutUnsubs = [
    subscribeKey(ui.uiState, "grid_layout", apply),
    subscribeKey(ui.uiState, "layout_css_grid", apply),
    subscribeKey(ui.uiState, "grid_shell_width", apply),
    subscribeKey(ui.uiState, "grid_shell_height", apply),
  ];
  apply();
}

import { MODAL_IDS } from "../modalIds.js";
import { deserializeReactor, calculateLayoutCostFromData } from "../domain/blueprint.js";
import {
  emptyLayoutsListTemplate,
  myLayoutsModalTemplate,
  myLayoutsTableRowTemplate,
