function contextModalTemplate(tile, onSell, onClose) {
  const part = tile?.part;
  if (!part) return nothing;
  const stats = [];
  if (part.power) stats.push(`Power: ${part.power}`);
  if (part.heat) stats.push(`Heat: ${part.heat}`);
  if (part.ticks) stats.push(`Ticks: ${part.ticks}`);
  const bodyContent = stats.length > 0
    ? html`<div>${stats.map((s, i) => html`${escapeHtml(s)}${i < stats.length - 1 ? html`<br>` : nothing}`)}</div>`
    : html`<div>No stats available</div>`;
  return contextLayout({
    partTitle: part.title || "Part",
    bodyContent,
    onClose,
    onSell,
  });
}

export { MODAL_IDS } from "../modalIds.js";

class ModalOrchestration {
  constructor() {
    this.ui = null;
    this._handlers = new Map();
    this._activeContextTile = null;
    this._modalRoot = null;
    this._settingsActiveTab = "audio";
    this._settingsState = proxy({ activeTab: "audio", notificationPermission: "default" });
    this._settingsUnmount = null;
    this._quickStartPage = 1;
    this._quickStartGame = null;
    this._settingsVisible = false;
  }

  init(ui) {
    this.ui = ui;
    const root = typeof document !== "undefined" ? document.getElementById("modal-root") : null;
    if (root instanceof HTMLDialogElement && !root.dataset.boundGameCancel) {
      root.dataset.boundGameCancel = "1";
      root.addEventListener("cancel", (e) => {
        e.preventDefault();
        ui?.modalOrchestrator?.hideModal?.(modalUi.activeModal);
      });
    }
    this._registerHandlers();
  }

  _resolveModalRoot() {
    if (!this._modalRoot) {
      this._modalRoot = (this.ui ? getUiElement(this.ui, "modal-root") : null) ?? (typeof document !== "undefined" ? document.getElementById("modal-root") : null);
    }
    return this._modalRoot;
  }

  _openLitModal(template) {
    const root = this._resolveModalRoot();
    if (!root) return;
    render(template, root);
    syncModalDialogOpen(root, true);
  }

  _closeLitModal() {
    const root = this._resolveModalRoot();
    if (!root) return;
    render(nothing, root);
    syncModalDialogOpen(root, false);
  }

  _registerHandlers() {
    const ui = this.ui;
    this._handlers.set(MODAL_IDS.CONTEXT, {
      show: (p) => this._showContextModal(p?.tile),
      hide: () => this._hideContextModal(),
    });
    this._handlers.set(MODAL_IDS.PRESTIGE, {
      show: (p) => this._showPrestigeModal(p),
      hide: () => this._hidePrestigeModal(),
    });
    this._handlers.set(MODAL_IDS.COPY_PASTE, {
      show: (p) => this._showCopyPasteModal(p),
      hide: () => this._hideCopyPasteModal(),
    });
    this._handlers.set(MODAL_IDS.WELCOME_BACK, {
      show: (p) => this._showWelcomeBackModal(p),
      hide: () => this._closeLitModal(),
    });
    this._handlers.set(MODAL_IDS.QUICK_START, {
      show: (p) => this._showQuickStartModal(p?.game),
      hide: () => this._hideQuickStartModal(),
    });
    this._handlers.set(MODAL_IDS.DETAILED_QUICK_START, {
      show: () => this._showQuickStartModal(ui?.game, true),
      hide: () => this._hideQuickStartModal(),
    });
    this._handlers.set(MODAL_IDS.REACTOR_FAILED_TO_START, {
      show: (p) => this._showReactorFailedToStartModal(p),
      hide: () => this._hideReactorFailedToStartModal(),
    });
    this._handlers.set(MODAL_IDS.LOGIN, {
      show: () => ui?.userAccountUI?.showLoginModal?.(),
      hide: () => {},
    });
    this._handlers.set(MODAL_IDS.PROFILE, {
      show: () => ui?.userAccountUI?.showProfileModal?.(),
      hide: () => {},
    });
    this._handlers.set(MODAL_IDS.LOGOUT, {
      show: () => ui?.userAccountUI?.showLogoutModal?.(),
      hide: () => {},
    });
    this._handlers.set(MODAL_IDS.SETTINGS, {
      show: () => this._showSettingsModal(),
      hide: () => this._hideSettingsModal(),
    });
    this._handlers.set(MODAL_IDS.LAYOUT_VIEW, {
      show: (p) => this._showLayoutViewModal(p),
      hide: () => this._hideLayoutViewModal(),
    });
    this._handlers.set(MODAL_IDS.MY_LAYOUTS, {
      show: () => this._showMyLayoutsModal(),
      hide: () => this._hideMyLayoutsModal(),
    });
  }

  showModal(modalId, payload = {}) {
    if (modalId !== MODAL_IDS.SETTINGS && modalId !== MODAL_IDS.MY_LAYOUTS) {
      setModalDrawerOpen(false);
    }
    modalUi.activeModal = modalId;
    modalUi.payload = payload ?? null;
    const handler = this._handlers.get(modalId);
    if (!handler?.show) return undefined;
    return handler.show(payload);
  }

  hideModal(modalId) {
    if (modalId == null) return;
    const handler = this._handlers.get(modalId);
    if (!handler?.hide) return;
    handler.hide();
    if (modalUi.activeModal === modalId) {
      modalUi.activeModal = null;
      modalUi.payload = null;
    }
  }

  isModalVisible(modalId) {
    if (modalId === MODAL_IDS.SETTINGS) return this._settingsVisible;
    return modalUi.activeModal === modalId;
  }

  _renderContextModal() {
    if (!this._resolveModalRoot()) return;
    const tile = this._activeContextTile;
    const onSell = async () => {
      this.ui?.deviceFeatures?.heavyVibration?.();
      const game = this.ui?.game;
      if (game && tile?.part) {
        game.state.intent_queue.push({
          action: "SELL_PART",
          payload: { row: tile.row, col: tile.col },
        });
        await game.engine?.consumeIntentQueueAsync?.();
        this.ui?.gridCanvasRenderer?.markTileDirty(tile.row, tile.col);
        this.hideModal(MODAL_IDS.CONTEXT);
      }
    };
    const onClose = () => {
      this.ui?.deviceFeatures?.lightVibration?.();
      this.hideModal(MODAL_IDS.CONTEXT);
    };
    if (tile) this._openLitModal(contextModalTemplate(tile, onSell, onClose));
    else this._closeLitModal();
  }

  _showContextModal(tile) {
    if (!this.ui || !tile?.part) return;
    this._resolveModalRoot();
    this._activeContextTile = tile;
    this._renderContextModal();
    this.ui.deviceFeatures?.lightVibration?.();
    const handle = this._modalRoot?.querySelector(".context-modal-handle");
    if (handle) {
      let startY = 0;
      const onEnd = (e) => {
        if (e.changedTouches[0].clientY - startY > 60) this.hideModal(MODAL_IDS.CONTEXT);
      };
      handle.addEventListener("touchstart", (e) => { startY = e.touches[0].clientY; }, { passive: true });
      handle.addEventListener("touchend", onEnd, { passive: true });
    }
  }

  _hideContextModal() {
    this._activeContextTile = null;
    this._renderContextModal();
  }

  _showPrestigeModal(payload) {
    const { mode } = payload ?? {};
    if (!this.ui?.game) return;

    const game = this.ui.game;
    const totalEp = game.state.total_exotic_particles || 0;
    const epFromWeave = game.state?.session_ep_weave ?? 0;
    const preservedUpgrades = game.upgradeset.getAllUpgrades().filter((u) => u.base_ecost && u.level > 0).length;
    const prestigeMultiplier = game.getPrestigeMultiplier ? game.getPrestigeMultiplier() : 1;

    const onCancel = () => this.hideModal(MODAL_IDS.PRESTIGE);
    const onConfirm = (confirmedMode) => {
      this.hideModal(MODAL_IDS.PRESTIGE);
      if (confirmedMode === "refund") {
        game.rebootActionDiscardExoticParticles();
      } else {
        game.rebootActionKeepExoticParticles();
      }
    };

    this._openLitModal(
      prestigeModalTemplate(
        { mode, totalEp, epFromWeave, preservedUpgrades, prestigeMultiplier },
        onConfirm,
        onCancel
      )
    );
  }

  _hidePrestigeModal() {
    this._closeLitModal();
  }

  _showCopyPasteModal(payload) {
    if (payload?.action === "sell") {
      this._showSellModal(payload);
    }
  }

  _showSellModal(payload) {
    const ui = this.ui;
    const { summary = [], checkedTypes = {}, previousPauseState = false } = payload || {};
    openCopyPasteDialogHost();
    const refs = getCopyPasteRefs();
    if (!refs) return;
    const { modal: modalEl, modalTitle, modalText, modalCost, confirmBtn, closeBtn } = refs;

    modalTitle.textContent = "Sell Reactor Parts";
    confirmBtn.textContent = "Sell Selected";

    if (modalText) {
      modalText.classList.add("hidden");
      modalText.style.display = "none";
      modalText.style.visibility = "hidden";
      modalText.style.opacity = "0";
      modalText.style.height = "0";
      modalText.style.overflow = "hidden";
    }

    modalEl.dataset.previousPauseState = previousPauseState;

    const updateSellSummary = () => {
      const filteredSummary = summary.filter(item => checkedTypes[item.id] !== false);
      const totalSellValue = filteredSummary.reduce((sum, item) => sum + item.total, 0);
      const onSlotClick = (ids, checked) => {
        ids.forEach(id => { checkedTypes[id] = !checked; });
        updateSellSummary();
      };
      const componentTemplate = renderComponentIcons(summary, { showCheckboxes: true, checkedTypes }, onSlotClick);
      const costTemplate = totalSellValue > 0
        ? html`<div style="margin-top: 10px; color: rgb(76 175 80); font-weight: bold;">Total Sell Value: $${fmt(totalSellValue)}</div>`
        : html`<div style="margin-top: 10px; color: rgb(255 107 107); font-weight: bold;">No parts selected</div>`;
      render(html`${componentTemplate}${costTemplate}`, modalCost);
      confirmBtn.disabled = totalSellValue === 0;
    };

    confirmBtn.classList.remove("hidden");
    confirmBtn.disabled = false;
    confirmBtn.style.backgroundColor = "var(--canvas-confirm-danger)";
    confirmBtn.onclick = async () => {
      const tilesToSell = [];
      ui.game.tileset.tiles_list.forEach(tile => {
        if (tile.enabled && tile.part && checkedTypes[tile.part.id] !== false) {
          tilesToSell.push(tile);
        }
      });
      const totalSellValue = tilesToSell.reduce((sum, tile) => sum + (tile.calculateSellValue?.() ?? tile.part.cost), 0);
      for (let i = 0; i < tilesToSell.length; i++) {
        const t = tilesToSell[i];
        ui.game.state.intent_queue.push({
          action: "SELL_PART",
          payload: { row: t.row, col: t.col },
        });
      }
      await ui.game.engine?.consumeIntentQueueAsync?.();
      ui.game.reactor.updateStats();
      confirmBtn.textContent = `Sold $${fmt(totalSellValue)}`;
      confirmBtn.style.backgroundColor = "var(--canvas-confirm-success)";
      setTimeout(() => {
        this.hideModal(MODAL_IDS.COPY_PASTE);
        confirmBtn.style.backgroundColor = "var(--canvas-confirm-action)";
      }, 1500);
    };

    closeBtn.onclick = () => this.hideModal(MODAL_IDS.COPY_PASTE);

    const dialogRoot = this._resolveModalRoot();
    if (dialogRoot && !dialogRoot._sellModalBackdropBound) {
      dialogRoot._sellModalBackdropBound = true;
      dialogRoot.addEventListener("click", (e) => {
        if (e.target === dialogRoot) this.hideModal(MODAL_IDS.COPY_PASTE);
      });
    }
    updateSellSummary();
  }

  _hideCopyPasteModal() {
    hideCopyPasteModal(this.ui);
  }

  _showWelcomeBackModal(payload) {
    if (!this.ui?.game) return Promise.resolve();
    if (!this._resolveModalRoot()) return Promise.resolve();

    const game = this.ui.game;
    game.pause();

    return new Promise((resolve) => {
      const handleClose = (mode) => {
        if (mode === "fast-forward" && game.engine) game.engine.beginFastForwardCatchup();

        if (game) {
          game.onToggleStateChange?.("pause", false);
        }
        this.hideModal(MODAL_IDS.WELCOME_BACK);
        resolve(mode);
      };

      const onFastForward = () => handleClose("fast-forward");
      const onDismiss = () => handleClose("fast-forward");

      const keyHandler = (e) => {
        if (e.key === "Escape") {
          document.removeEventListener("keydown", keyHandler);
          onDismiss();
        }
      };
      document.addEventListener("keydown", keyHandler);

      const wrappedClose = (mode) => {
        document.removeEventListener("keydown", keyHandler);
        handleClose(mode);
      };

      this._openLitModal(
        welcomeBackModalTemplate(
          payload,
          () => wrappedClose("fast-forward"),
          () => wrappedClose("fast-forward")
        )
      );
    });
  }

  _renderSettingsModal() {
    if (!this._resolveModalRoot()) return;
    if (this._settingsUnmount) {
      this._settingsUnmount();
      this._settingsUnmount = null;
    }
    const onClose = () => this.hideModal(MODAL_IDS.SETTINGS);
    const onTabClick = (tabId) => {
      if (this._settingsState.activeTab === tabId) return;
      this._settingsState.activeTab = tabId;
    };
    const onAfterRender = () => {
      abortSettingsListeners();
      const signal = getAbortSignal();
      const overlay = this._modalRoot?.firstElementChild;
      if (overlay) {
        bindSettingsEvents(overlay, this._settingsContext, signal);
        const header = overlay.querySelector(".settings-header");
        if (header) {
          let startY = 0;
          header.addEventListener("touchstart", (e) => { startY = e.touches[0].clientY; }, { passive: true });
          header.addEventListener("touchend", (e) => {
            if (e.changedTouches[0].clientY - startY > 60) onClose();
          }, { passive: true });
        }
      }
    };
    this._settingsUnmount = bindLitRenderMultiStates(
      [preferences, this._settingsState],
      () => settingsModalTemplate(this._settingsState, onTabClick, onClose),
      this._modalRoot,
      onAfterRender
    );
  }

  _showSettingsModal() {
    if (!this.ui) return;
    if (!this._resolveModalRoot()) return;
    this._settingsState.activeTab = "audio";
    this._settingsState.notificationPermission = typeof Notification !== "undefined" ? Notification.permission : "default";
    this._settingsContext = createSettingsContext(this.ui, this);
    const root = this._modalRoot;
    if (root && !root._settingsCancelBound) {
      root._settingsCancelBound = true;
      root.addEventListener("cancel", (e) => {
        e.preventDefault();
        this.hideModal(MODAL_IDS.SETTINGS);
      });
      root.addEventListener("click", (e) => {
        if (e.target === root) this.hideModal(MODAL_IDS.SETTINGS);
      });
    }
    this._settingsVisible = true;
    setModalDrawerOpen(true);
    this._renderSettingsModal();
    syncModalDialogOpen(this._modalRoot, true);
  }

  _hideSettingsModal() {
    this._settingsVisible = false;
    setModalDrawerOpen(false);
    if (this._settingsUnmount) {
      this._settingsUnmount();
      this._settingsUnmount = null;
    }
    abortSettingsListeners();
    if (this._settingsKeyHandler) {
      this._settingsKeyHandler = null;
    }
    const game = this.ui?.game;
    if (game) {
      enqueueWarningStop(game);
      game.audio?.stopTestSound?.();
    }
    this._closeLitModal();
    const menuBtn = document.getElementById("menu_tab_btn");
    if (menuBtn) menuBtn.classList.remove("active");
    const settingsTopBtn = document.getElementById("settings_btn");
    if (settingsTopBtn) settingsTopBtn.classList.remove("active");
    const currentPageId = game?.router?.currentPageId;
    if (currentPageId) {
      const bottomNav = document.getElementById("bottom_nav");
      if (bottomNav) {
        const pageBtn = bottomNav.querySelector(`button[data-page="${currentPageId}"]`);
        if (pageBtn) pageBtn.classList.add("active");
      }
    }
  }

  _showReactorFailedToStartModal(payload) {
    const game = payload?.game ?? this.ui?.game;
    if (!game) return;
    if (!this._resolveModalRoot()) return;

    const errorMessage = payload?.error ?? null;
    if (this.ui?.uiState) this.ui.uiState.reactor_failed_error = errorMessage;

    const onTryAgain = () => {
      if (game.engine) game.engine.start();
      this._hideReactorFailedToStartModal(false);
    };
    const onDismiss = () => this._hideReactorFailedToStartModal(true);
    this._openLitModal(reactorFailedToStartTemplate({ errorMessage, onTryAgain, onDismiss }));
  }

  _showQuickStartModal(game, isDetailed = false) {
    if (!this._resolveModalRoot()) return;

    this._quickStartPage = 1;
    this._quickStartGame = game;

    const onClose = () => {
      StorageUtils.set(STORAGE_KEYS.QUICK_START_SHOWN, 1);
      if (this._quickStartGame?.tutorialManager && !StorageUtils.get("reactorTutorialCompleted")) {
        this._quickStartGame.tutorialManager.start();
      }
      this.hideModal(MODAL_IDS.QUICK_START);
    };
    const onMoreDetails = () => {
      this._quickStartPage = 2;
      this._openLitModal(
        quickStartTemplate(this._quickStartPage, onClose, onMoreDetails, onBack)
      );
    };
    const onBack = () => {
      this._quickStartPage = 1;
      this._openLitModal(
        quickStartTemplate(this._quickStartPage, onClose, onMoreDetails, onBack)
      );
    };

    this._openLitModal(quickStartTemplate(this._quickStartPage, onClose, onMoreDetails, onBack));
  }

  _hideQuickStartModal() {
    this._quickStartGame = null;
    this._closeLitModal();
  }

  showSettings() {
    this.showModal(MODAL_IDS.SETTINGS);
  }

  showWelcomeBackModal(offlineMs, tickEquivalent) {
    return this.showModal(MODAL_IDS.WELCOME_BACK, { offlineMs, tickEquivalent });
  }

  showPrestigeModal(mode) {
    this.showModal(MODAL_IDS.PRESTIGE, { mode });
  }

  hidePrestigeModal() {
    this.hideModal(MODAL_IDS.PRESTIGE);
  }

  showContextModal(tile) {
    this.showModal(MODAL_IDS.CONTEXT, { tile });
  }

  hideContextModal() {
    this.hideModal(MODAL_IDS.CONTEXT);
  }

  hideCopyPasteModal() {
    this.hideModal(MODAL_IDS.COPY_PASTE);
  }

  _hideReactorFailedToStartModal(pauseGame = false) {
    const game = this.ui?.game;
    if (pauseGame && game) {
      game.pause();
      game.onToggleStateChange?.("pause", true);
    }
    if (this.ui?.uiState) this.ui.uiState.reactor_failed_error = null;
    this._closeLitModal();
    if (modalUi.activeModal === MODAL_IDS.REACTOR_FAILED_TO_START) {
      modalUi.activeModal = null;
      modalUi.payload = null;
    }
  }

  _showLayoutViewModal(payload) {
    const { layoutJson, stats } = payload ?? {};
    if (!this.ui?.game) return;
    if (!this._resolveModalRoot()) return;

    const onClose = () => this.hideModal(MODAL_IDS.LAYOUT_VIEW);
    this._openLitModal(layoutViewTemplate(layoutJson, stats, this.ui.game, onClose));
  }

  _hideLayoutViewModal() {
    this._closeLitModal();
  }

  _showMyLayoutsModal() {
    if (!this.ui) return;
    if (!this._resolveModalRoot()) return;

    const onClose = () => this.hideModal(MODAL_IDS.MY_LAYOUTS);
    const list = getMyLayouts();
    this._openLitModal(myLayoutsTemplate(this.ui, list, fmt, onClose));
  }

  _hideMyLayoutsModal() {
    setModalDrawerOpen(false);
    this._closeLitModal();
  }
}

export function createModalOrchestrator() {
  return new ModalOrchestration();
}

﻿import { html, render } from "lit-html";
import { MOBILE_BREAKPOINT_PX } from "../constants/ui-constants.js";
import { logger } from "../core/logger.js";
import { numFormat as fmt } from "../format/numbers.js";
import { actions } from "../store.js";
import { bindLitRenderMulti } from "../dom/lit-reactive.js";
import { PartButton, partsModuleInfoCardTemplate } from "./button-factory.js";
import {
  partsPanelLayoutTemplate,
  partsPanelEmptyTabContentTemplate,
  partsPanelTabContentTemplate,
  quickSelectSlotTemplate,
} from "../templates/uiComponentsTemplates.js";
import { getUiElement } from "./page-dom.js";
import { classMap, styleMap, repeat } from "../dom/lit.js";

function getPartsSectionElement(ui) {
  return getUiElement(ui, "parts_section");
}

export function updatePartsPanelBodyClass(ui) {
  const partsSection = getPartsSectionElement(ui);
  if (ui.uiState && partsSection) {
    ui.uiState.parts_panel_right_side = partsSection.classList.contains("right-side");
  }
}

export function togglePartsPanelForBuildButton(ui) {
  ui.deviceFeatures?.heavyVibration?.();
  if (ui.game) actions.enqueueEffect(ui.game, { kind: "sfx", id: "metal_clank", a: 0.8, b: -0.7, context: "global" });
  const partsSection = getPartsSectionElement(ui);
  if (partsSection && ui.uiState) {
    ui.uiState.parts_panel_collapsed = !ui.uiState.parts_panel_collapsed;
    updatePartsPanelBodyClass(ui);
  }
}

const CATEGORY_MAP = {
  power: ["cell", "reflector", "capacitor", "particle_accelerator"],
  heat: ["vent", "heat_exchanger", "heat_inlet", "heat_outlet", "coolant_cell", "reactor_plating", "valve"],
};

const CATEGORY_TO_CONTAINER = {
  coolant_cell: "coolantCells",
  reactor_plating: "reactorPlatings",
  heat_exchanger: "heatExchangers",
  heat_inlet: "heatInlets",
  heat_outlet: "heatOutlets",
  particle_accelerator: "particleAccelerators",
};

function getContainerKey(part) {
  if (CATEGORY_TO_CONTAINER[part.category]) return CATEGORY_TO_CONTAINER[part.category];
  if (part.category === "valve" && part.valve_group) return part.valve_group + "Valves";
  return part.category + "s";
}

function getPartsByContainer(partset, tabId, unlockManager) {
  const categories = CATEGORY_MAP[tabId] || [];
  const byContainer = new Map();
  for (const cat of categories) {
    const parts = partset.getPartsByCategory(cat);
    for (const part of parts) {
      if (unlockManager && !unlockManager.shouldShowPart(part)) continue;
      const key = getContainerKey(part);
      if (!byContainer.has(key)) byContainer.set(key, []);
      byContainer.get(key).push(part);
    }
  }
  return byContainer;
}

export function unlockAllPartsForTesting(ui) {
  if (!ui.game?.partset?.partsArray) return;
  const typeLevelCombos = new Set();
  ui.game.partset.partsArray.forEach((part) => {
    if (part.type && part.level) {
      typeLevelCombos.add(`${part.type}:${part.level}`);
    }
  });
  typeLevelCombos.forEach((combo) => {
    ui.game.placedCounts[combo] = 10;
  });
  ui.game.partset.check_affordability(ui.game);
  refreshPartsPanel(ui);
}

export function refreshPartsPanel(ui) {
  if (ui.game?.state && typeof ui.game.state.parts_panel_version === "number") {
    ui.game.state.parts_panel_version++;
  }
}

export function onPartsPanelActiveTabChanged(ui, _tabId) {
  refreshPartsPanel(ui);
}

function createPartTemplateHandlers(ui, partset, unlockManager, selectedPartId) {
  const game = ui.game;
  return (part) => {
    const onClick = () => {
      if (part.affordable) {
        if (ui.help_mode_active && ui.tooltipManager) ui.tooltipManager.show(part, null, true);
        game?.emit?.("partClicked", { part });
        ui.stateManager.setClickedPart(part);
      } else if (ui.tooltipManager) {
        ui.tooltipManager.show(part, null, true);
      }
    };
    const unlocked = !unlockManager || unlockManager.isPartUnlocked(part);
    const opts = {
      locked: !unlocked,
      doctrineLocked: !unlocked && partset?.isPartDoctrineLocked?.(part),
      tierProgress: !unlocked ? `${Math.min(unlockManager?.getPreviousTierCount(part) ?? 0, 10)}/10` : "",
      partActive: part.id === selectedPartId,
    };
    return PartButton(part, onClick, opts);
  };
}

function buildPartsTabContent(ui, partset, unlockManager, activeTab, powerActive, heatActive) {
  if (!partset) return partsPanelEmptyTabContentTemplate();
  const byContainer = getPartsByContainer(partset, activeTab, unlockManager);
  const selectedPartId = ui.stateManager.getClickedPart()?.id ?? null;
  const partTemplate = createPartTemplateHandlers(ui, partset, unlockManager, selectedPartId);
  const grid = (id) => html`<div id=${id} class="item-grid">${repeat(byContainer.get(id) ?? [], (p) => p.id, partTemplate)}</div>`;
  return partsPanelTabContentTemplate({ powerActive, heatActive, grid });
}

function buildPartsPanelLayoutTemplate(ui, uiState) {
  const game = ui.game;
  const partset = game?.partset;
  const unlockManager = game?.unlockManager;
  const activeTab = uiState?.active_parts_tab ?? "power";
  const switchTab = (tabId) => { if (ui.uiState) ui.uiState.active_parts_tab = tabId; };
  const onHelpToggle = () => {
    ui.setHelpModeActive(!ui.help_mode_active);
    refreshPartsPanel(ui);
  };
  const powerActive = activeTab === "power";
  const heatActive = activeTab === "heat";
  const tabContent = buildPartsTabContent(ui, partset, unlockManager, activeTab, powerActive, heatActive);

  const selectedPartId = uiState?.interaction?.selectedPartId ?? null;
  const selPart = selectedPartId && partset ? partset.getPartById(selectedPartId) : null;
  const moduleInfoContent = selPart
    ? partsModuleInfoCardTemplate(selPart)
    : html`<span class="parts-module-info-empty">— Select a module —</span>`;

  return partsPanelLayoutTemplate({
    powerActive,
    heatActive,
    helpModeActive: ui.help_mode_active,
    onSwitchPower: () => switchTab("power"),
    onSwitchHeat: () => switchTab("heat"),
    onHelpToggle,
    tabContent,
    moduleInfoContent,
  });
}

export function setupPartsTabs(ui) {
  if (ui._partsPanelReactiveMounted) {
    const root = document.getElementById("parts_panel_reactive_root");
    if (root?.isConnected) return;
    if (typeof ui._partsPanelReactiveUnmount === "function") {
      try { ui._partsPanelReactiveUnmount(); } catch (_) {}
      ui._partsPanelReactiveUnmount = null;
    }
    ui._partsPanelReactiveMounted = false;
  }
  const root = document.getElementById("parts_panel_reactive_root");
  if (!root || !ui.uiState) return;
  const subscriptions = [
    { state: ui.game?.state, keys: ["current_money", "current_exotic_particles", "parts_panel_version"] },
    { state: ui.uiState, keys: ["active_parts_tab", "parts_panel_collapsed"] },
    { state: ui.uiState?.interaction, keys: ["selectedPartId"] },
  ].filter((s) => s.state != null);
  if (subscriptions.length === 0) return;
  const renderFn = () => buildPartsPanelLayoutTemplate(ui, ui.uiState);
  ui._partsPanelReactiveUnmount = bindLitRenderMulti(subscriptions, renderFn, root);
  ui._partsPanelReactiveMounted = true;
  if (!ui._layoutUnmounts) ui._layoutUnmounts = [];
  ui._layoutUnmounts.push(ui._partsPanelReactiveUnmount);
}

const PLACEMENT_MACROS = [
  { id: "row", label: "ROW", title: "Fill row (Ctrl+click)" },
  { id: "col", label: "COL", title: "Fill column (Alt+click)" },
  { id: "checker", label: "CHK", title: "Checkerboard (Ctrl+Alt+click)" },
  { id: "fill", label: "FILL", title: "Fill matching parts (Shift+click)" },
  { id: null, label: "1×", title: "Single tile placement" },
];

function macroFabLabel(active) {
  if (!active) return "1×";
  const match = PLACEMENT_MACROS.find((m) => m.id === active);
  return match?.label ?? "1×";
}

function setMacroPopoverOpen(open) {
  const popover = document.getElementById("macro_toolbar_popover");
  const fab = document.getElementById("macro_toolbar_fab");
  if (!popover || !fab) return;
  popover.classList.toggle("hidden", !open);
  fab.setAttribute("aria-expanded", open ? "true" : "false");
}

function syncMacroFabChrome(ui) {
  const fab = document.getElementById("macro_toolbar_fab");
  const labelEl = document.getElementById("macro_toolbar_fab_label");
  if (!fab || !labelEl || !ui?.uiState) return;
  const active = ui.uiState.interaction.placementMacro;
  labelEl.textContent = macroFabLabel(active);
  fab.classList.toggle("is-macro-active", !!active);
  fab.title = active
    ? `Macro: ${macroFabLabel(active)} (tap to change)`
    : "Placement macros";
}

export function setupMacroToolbar(ui) {
  const popover = document.getElementById("macro_toolbar_popover");
  const fab = document.getElementById("macro_toolbar_fab");
  if (!popover || !fab || !ui.uiState) return;
  const active = ui.uiState.interaction.placementMacro;
  const template = html`
    ${PLACEMENT_MACROS.map(
      (m) => html`
        <button
          type="button"
          role="menuitemradio"
          class=${classMap({ "macro-toolbar-btn": true, "is-active": active === m.id })}
          data-macro=${m.id ?? ""}
          title=${m.title}
          aria-label=${m.title}
          aria-checked=${active === m.id ? "true" : "false"}
        >${m.label}</button>
      `
    )}
  `;
  render(template, popover);
  syncMacroFabChrome(ui);

  if (!ui._macroToolbarBound) {
    ui._macroToolbarBound = true;
    fab.addEventListener("click", (e) => {
      e.preventDefault();
      e.stopPropagation();
      const isOpen = !popover.classList.contains("hidden");
      setMacroPopoverOpen(!isOpen);
      ui.deviceFeatures?.lightVibration?.();
    });
    popover.addEventListener("click", (e) => {
      const btn = e.target.closest("[data-macro]");
      if (!btn || !popover.contains(btn)) return;
      e.stopPropagation();
      const raw = btn.getAttribute("data-macro");
      const next = raw || null;
      const current = ui.uiState.interaction.placementMacro;
      ui.uiState.interaction.placementMacro = next && next === current ? null : next;
      ui.deviceFeatures?.lightVibration?.();
      setMacroPopoverOpen(false);
      updateMacroToolbar(ui);
    });
    document.addEventListener("click", (e) => {
      const anchor = document.getElementById("macro_toolbar_anchor");
      if (!anchor || anchor.contains(e.target)) return;
      setMacroPopoverOpen(false);
    });
  }
}

export function updateMacroToolbar(ui) {
  setupMacroToolbar(ui);
}

export function updateQuickSelectSlots(ui) {
  ui.stateManager.normalizeQuickSelectSlotsForUnlock();
  const slots = ui.stateManager.getQuickSelectSlots();
  const partset = ui.game?.partset;
  const selectedPartId = ui.stateManager.getClickedPart()?.id ?? null;
  const root = document.getElementById("quick_select_slots_root");
  if (!root) return;
  const slotTemplate = (slot, i) => {
    const { partId, locked } = slot || { partId: null, locked: false };
    const part = partId && partset ? partset.getPartById(partId) : null;
    const slotClass = classMap({
      "quick-select-slot": true,
      locked: !!locked,
      unaffordable: !!(part && !part.affordable),
      "is-selected": partId !== null && partId === selectedPartId,
    });
    const ariaLabel = part ? (locked ? `Unlock ${part.title}` : `Select ${part.title}`) : `Recent part ${i + 1}`;
    const costText = part ? (part.erequires ? `${fmt(part.cost)} EP` : `$${fmt(part.cost)}`) : "";
    const iconStyle = part?.getImagePath ? styleMap({ backgroundImage: `url('${part.getImagePath()}')` }) : {};
    return quickSelectSlotTemplate({
      slotClass,
      index: i,
      ariaLabel,
      hasIcon: !!part?.getImagePath,
      iconStyle,
      hasPart: !!part,
      costText,
    });
  };
  const template = html`${repeat(slots, (_, i) => i, slotTemplate)}`;
  try {
    render(template, root);
  } catch (err) {
    const msg = err?.message ?? "";
    if (msg.includes("ChildPart") && msg.includes("parentNode")) {
      render(html``, root);
      render(template, root);
    } else {
      throw err;
    }
  }
}

export function closePartsPanel(ui) {
  if (ui.uiState) ui.uiState.parts_panel_collapsed = true;
}

export function teardownPartsPanel(ui) {
  if (ui?._partsPanelAbortController) {
    ui._partsPanelAbortController.abort();
    ui._partsPanelAbortController = null;
  }
}

export function initializePartsPanel(ui) {
  const panel = getPartsSectionElement(ui);
  if (!panel) return;

  teardownPartsPanel(ui);
  ui._partsPanelAbortController = new AbortController();
  const { signal } = ui._partsPanelAbortController;
  window.addEventListener("resize", () => {
    const isCurrentlyMobile = window.innerWidth <= MOBILE_BREAKPOINT_PX;
    if (ui.uiState) ui.uiState.parts_panel_collapsed = isCurrentlyMobile;
  }, { signal });

  const isMobileOnLoad = window.innerWidth <= MOBILE_BREAKPOINT_PX;
  if (ui.uiState) ui.uiState.parts_panel_collapsed = isMobileOnLoad;
  logger.log("debug", "ui", "[Parts Panel Init]", isMobileOnLoad ? "Mobile detected - added collapsed class" : "Desktop detected - removed collapsed class");
  logger.log("debug", "ui", "[Parts Panel Init] Final state - collapsed:", panel.classList.contains("collapsed"));
  updatePartsPanelBodyClass(ui);

  const closeBtn = document.getElementById("parts_close_btn");
  if (closeBtn && !closeBtn.hasAttribute("data-listener-attached")) {
    closeBtn.setAttribute("data-listener-attached", "true");
    closeBtn.addEventListener("click", () => {
      closePartsPanel(ui);
    }, { signal });
  }

  ui.stateManager.updatePartsPanelToggleIcon(null);
}

export function setupPartsPanel(ui) {
  setupPartsTabs(ui);
  initializePartsPanel(ui);
}

const PREVIEW_MAX_WIDTH = 160;
const PREVIEW_MAX_HEIGHT = 120;
const PREVIEW_MIN_TILE_SIZE = 2;
const GHOST_ALPHA = 0.35;

function getPreviewDimensions(rows, cols) {
  const tileSize = Math.max(PREVIEW_MIN_TILE_SIZE, Math.min(Math.floor(PREVIEW_MAX_WIDTH / cols), Math.floor(PREVIEW_MAX_HEIGHT / rows)));
  return { tileSize, w: cols * tileSize, h: rows * tileSize };
}

function drawPreviewTileBackground(ctx, x, y, tileSize) {
  ctx.fillStyle = "rgb(20 20 20)";
  ctx.strokeStyle = "rgb(40 40 40)";
  ctx.fillRect(x, y, tileSize, tileSize);
  ctx.strokeRect(x, y, tileSize, tileSize);
}

function drawPreviewTilePart(ctx, img, x, y, tileSize, ghost) {
  if (!img || !img.complete || !img.naturalWidth) return;
  if (ghost) ctx.globalAlpha = GHOST_ALPHA;
  ctx.drawImage(img, x, y, tileSize, tileSize);
  if (ghost) ctx.globalAlpha = 1;
}

function createImageLoader() {
  const imgCache = new Map();
  return (path) => {
    if (imgCache.has(path)) return imgCache.get(path);
    if (typeof Image !== "function" || typeof document === "undefined") {
      imgCache.set(path, null);
      return null;
    }
    try {
      const img = new Image();
      img.src = path;
      imgCache.set(path, img);
      return img;
    } catch (_) {
      imgCache.set(path, null);
      return null;
    }
  };
}

function drawPreviewCell(ctx, opts) {
  const { layout, r, c, partset, loadImg, tileSize, affordableSet } = opts;
  const x = c * tileSize;
  const y = r * tileSize;
  drawPreviewTileBackground(ctx, x, y, tileSize);
  const cell = layout[r]?.[c];
  if (!cell?.id) return;
  const part = partset.getPartById(cell.id);
  if (!part) return;
  const path = typeof part.getImagePath === "function" ? part.getImagePath() : null;
  if (!path) return;
  const key = `${r},${c}`;
  const ghost = affordableSet != null && !affordableSet.has(key);
  drawPreviewTilePart(ctx, loadImg(path), x, y, tileSize, ghost);
}

export function renderLayoutPreview(partset, layout, canvasEl, affordableSet) {
  if (!layout?.length || !canvasEl || !partset) return;
  const rows = layout.length;
  const cols = layout[0]?.length ?? 0;
  if (cols === 0) return;
  const { tileSize, w, h } = getPreviewDimensions(rows, cols);
  canvasEl.width = w;
  canvasEl.height = h;
  const ctx = canvasEl.getContext("2d");
  if (!ctx) return;
  const loadImg = createImageLoader();
  const indices = Array.from({ length: rows * cols }, (_, i) => ({ r: Math.floor(i / cols), c: i % cols }));
  indices.forEach(({ r, c }) => drawPreviewCell(ctx, { layout, r, c, partset, loadImg, tileSize, affordableSet }));
}

export function buildPartSummary(partset, layout) {
  if (!partset || !layout) return [];
  const cells = layout.flatMap((row) => row || []).filter((cell) => cell && cell.id);
  const summary = cells.reduce((acc, cell) => {
    const key = `${cell.id}|${cell.lvl || 1}`;
    if (!acc[key]) {
      const part = partset.parts.get(cell.id);
      acc[key] = {
        id: cell.id,
        type: cell.t,
        lvl: cell.lvl || 1,
        title: part ? part.title : cell.id,
        unitPrice: part ? part.cost : 0,
        count: 0,
        total: 0,
      };
    }
    acc[key].count++;
    acc[key].total += acc[key].unitPrice;
    return acc;
  }, {});
  return Object.values(summary);
}

export function buildAffordableSet(affordableLayout) {
  if (!affordableLayout) return new Set();
  const keys = affordableLayout.flatMap((row, r) => (row || []).map((cell, c) => cell ? `${r},${c}` : null).filter(Boolean));
  return new Set(keys);
}

import { updateLeaderboardIcon } from "./ui-nav.js";
import { getGridCanvasRenderer } from "./grid-canvas-service.js";

export function getUiConfigDisplayValue(game, configKey) {
  if (configKey === "exotic_particles") return game?.exoticParticleManager?.exotic_particles;
  return game?.state?.[configKey];
}

export function snapUiDisplayValuesFromState(ui) {
  if (!ui.displayValues) return;
  const d = ui.displayValues;
  ["money", "heat", "power", "ep"].forEach((k) => {
    const o = d[k];
    if (o && typeof o.current === "number" && typeof o.target === "number") o.current = o.target;
  });
}

export function syncUiDisplayValueTargetsFromState(ui) {
  const game = ui.game;
  if (!game?.state || !ui.displayValues) return;
  const s = game.state;
  const d = ui.displayValues;
  const toNum = (v) => (v != null && typeof v.toNumber === "function" ? v.toNumber() : Number(v ?? 0));
  if (d.money) d.money.target = toNum(s.current_money);
  if (d.heat) d.heat.target = toNum(s.current_heat);
  if (d.power) d.power.target = toNum(s.current_power);
  if (d.ep) d.ep.target = toNum(game.exoticParticleManager?.exotic_particles ?? s.current_exotic_particles ?? 0);
}

export function applyUiStateToDom(ui) {
  const game = ui.game;
  const config = ui.var_objs_config;
  if (!config || !game?.state) return;
  for (const configKey of Object.keys(config)) {
    const val = getUiConfigDisplayValue(game, configKey);
    if (val === undefined) continue;
    const cfg = config[configKey];
    cfg?.onupdate?.(val);
  }
}

export function applyUiStateToDomForKeys(ui, keys) {
  const game = ui.game;
  const config = ui.var_objs_config;
  if (!config || !game) return;
  for (const configKey of keys) {
    const cfg = config[configKey];
    if (!cfg) continue;
    const val = getUiConfigDisplayValue(game, configKey);
    if (val === undefined) continue;
    cfg.onupdate?.(val);
  }
}

export function processUiUpdateQueue(ui) {
  syncUiDisplayValueTargetsFromState(ui);
  snapUiDisplayValuesFromState(ui);
  applyUiStateToDom(ui);
}

export function updateUiRollingNumbers(ui, _dt) {
  snapUiDisplayValuesFromState(ui);
}

export function startRenderLoop(ui, timestamp = 0) {
  if (ui._updateLoopStopped) return;
  if (typeof document === "undefined" || !document) return;
  if (typeof document.getElementById !== "function") return;
  if (!ui._lastUiTime) ui._lastUiTime = timestamp;
  ui._lastUiTime = timestamp;

  ui._firstFrameSyncDone = true;

  if (timestamp - ui.last_interface_update > ui.update_interface_interval) {
    ui.last_interface_update = timestamp;
    const gridRenderer = getGridCanvasRenderer();
    if (gridRenderer && ui.game) gridRenderer.render(ui.game);
    updateLeaderboardIcon(ui);
    ui.heatVisualsUI?.drawHeatFlowOverlay?.();
    ui.heatVisualsUI?.drawVoltagePlacementOverlay?.();
  }

  ui.update_interface_task = requestAnimationFrame((ts) => startRenderLoop(ui, ts));
}

