class TutorialRuntime {
  constructor(game) {
    this.game = game;
    this.currentStep = -1;
    this.overlay = null;
    this.callout = null;
    this._resumeStepIndex = null;
    this._claimStepActive = false;
    this.isMobile = () => typeof window !== "undefined" && window.innerWidth <= MOBILE_BREAKPOINT_PX;
    this.steps = [
      {
        key: "place_cell",
        message: "Click to select your Uranium Cell",
