function clearDesktopTooltipPosition(tooltipEl) {
  tooltipEl.style.top = "";
  tooltipEl.style.left = "";
  tooltipEl.style.right = "";
  tooltipEl.style.transform = "";
}

function getIconifyFn() {
  const numWithUnit = "(?:\\d[\\d,.]*?(?:\\s*[kKmMbBtTqQ])?|\\d[\\d,.]*?(?:e[+\\-]?\\d+)?)";
  const unitSpanSpecs = [
    ["power", "power-num", "power"],
    ["heat", "heat-num", "heat"],
    ["ticks?", "tick-num", "tick"],
  ];
  return (str) => {
    if (!str) return str;
    let s = str
      .replace(/\b(power|heat|ticks?)\b/gi, (m) => {
        const low = m.toLowerCase();
        const icon = low === "power" ? "power" : low === "heat" ? "heat" : "time";
        const alt = low.startsWith("tick") ? "tick" : low;
        return `${m} <img src='img/ui/icons/icon_${icon}.png' class='icon-inline' alt='${alt}'>`;
      })
      .replace(/\$(\d+)/g, "<img src='img/ui/icons/icon_cash.png' class='icon-inline' alt='cash'> $1")
      .replace(/\bEP\b/g, "🧬 $&");
    for (const [unitPat, cls, altLit] of unitSpanSpecs) {
      const re = new RegExp(`(\\b${numWithUnit}\\b)\\s+(${unitPat})\\s+(<img[^>]+alt=['\" ]${altLit}['\"][^>]*>)`, "gi");
      s = s.replace(re, `<span class="num ${cls}">$1</span> $2 $3`);
    }
    return s;
  };
}

function formatDescriptionBulleted(description, iconifyFn) {
  const raw = String(description || "").trim();
  const cleaned = raw.replace(/\.+$/, '');
  const parts = cleaned
    .split(/\.\s+(?=[A-Z(0-9])/g)
    .map(s => s.trim())
    .filter(Boolean)
    .map(s => s.replace(/\.+$/, ''));
  if (parts.length === 0) return '';
  return parts.map(line => `<div class="tooltip-bullet">${iconifyFn(line)}</div>`).join("");
}

function colorizeBonus(line, iconifyFn) {
  if (!line) return line;
  let result = line.replace(/([+-][0-9]+(?:\.[0-9]+)?(?:%|\/[a-z]+)?)/gi, (m) => `<span class="${m.startsWith("-") ? "neg" : "pos"}">${m}</span>`);
  result = result.replace(/\b(venting|max heat|transfer|EP heat cap)\b/gi, (m) => iconifyFn(m));
  return result
    .replace(/\bpower\b/gi, (m) => `${m} <img src='img/ui/icons/icon_power.png' class='icon-inline' alt='power'>`)
    .replace(/(?<!max\s)\bheat\b/gi, (m) => `${m} <img src='img/ui/icons/icon_heat.png' class='icon-inline' alt='heat'>`)
    .replace(/\bduration\b/gi, (m) => `${m} <img src='img/ui/icons/icon_time.png' class='icon-inline' alt='time'>`);
}

function getUpgradeBonusLines(obj, tile, game) {
  return getUpgradeBonusLinesCore(obj, { tile, game });
}

function setMaxOrLockedStatus(stats, obj, game) {
  if (obj.upgrade) {
    if (obj.level >= obj.max_level) stats.set("", "MAX");
    return;
  }
  if (obj.cost !== undefined && obj.erequires && !game.upgradeset.getUpgrade(obj.erequires)?.level) {
    stats.set("", "LOCKED");
  }
}

function setBaseHeatStats(stats, obj, tile) {
  const maxHeat = obj.containment || "∞";
  const maxHeatDisplay = maxHeat === "∞" ? maxHeat : fmt(maxHeat, 0);
  stats.set("Heat", `${fmt(tile.heat_contained || 0, 0)} / ${maxHeatDisplay}`);
}

function setVentCoolingStats(stats, segment) {
  const totalVentRate = segment.vents.reduce((sum, vent) => sum + vent.getEffectiveVentValue(), 0);
  stats.set("Cooling", `${fmt(totalVentRate, 1)}/tick`);
}

function setOutletTransferStats(stats, segment, game) {
  const totalOutletRate = segment.outlets.reduce((sum, o) => sum + o.getEffectiveTransferValue(), 0);
  const reactorFullness = game.reactor.max_heat > 0 ? game.reactor.current_heat / game.reactor.max_heat : 0;
  const effective = totalOutletRate * reactorFullness * (1 - segment.fullnessRatio);
  stats.set("Transfer", `${fmt(effective, 1)}/tick`);
}

function setInletTransferStats(stats, segment, game) {
  const totalInletRate = segment.inlets.reduce((sum, i) => sum + i.getEffectiveTransferValue(), 0);
  const reactorFullness = game.reactor.max_heat > 0 ? game.reactor.current_heat / game.reactor.max_heat : 0;
  const effective = totalInletRate * segment.fullnessRatio * (1 - reactorFullness);
  stats.set("Transfer", `${fmt(effective, 1)}/tick`);
}

function calculateSellValue(obj, tile) {
  let sell_value = obj.cost;
  if (obj.ticks > 0) {
    sell_value = Math.ceil((tile.ticks / obj.ticks) * obj.cost);
  } else if (obj.containment > 0) {
    sell_value = obj.cost - Math.ceil((tile.heat_contained / obj.containment) * obj.cost);
  }
  return sell_value;
}

function setHeatAndSegmentStats(stats, obj, tile, game) {
  if (!tile?.activated || (!obj.containment && tile.heat_contained <= 0)) return;
  setBaseHeatStats(stats, obj, tile);
  const pressureNote = inspectExchangerPressureFlow(tile);
  if (pressureNote) stats.set("Heat routing", pressureNote);
  if (!game.engine?.heatManager) return;
  const segment = game.engine.heatManager.getSegmentForTile(tile);
  if (!segment) return;
  stats.set("Segment", `${fmt(segment.fullnessRatio * 100, 1)}% full`);
  if (obj.category === "vent" && segment.vents.length > 0) {
    setVentCoolingStats(stats, segment);
  } else if (obj.category === "heat_outlet" && segment.outlets.length > 0) {
    setOutletTransferStats(stats, segment, game);
  } else if (obj.category === "heat_inlet" && segment.inlets.length > 0) {
    setInletTransferStats(stats, segment, game);
  }
}

function setTransferSellAndEpStats(stats, obj, tile) {
  if (!tile?.activated) return;
  if ((obj.category === "heat_outlet" || obj.category === "heat_inlet") && !stats.has("Transfer")) {
    stats.set("Max Transfer", `${fmt(tile.getEffectiveTransferValue(), 1)}/tick`);
  }
  if (obj.category !== "cell") {
    const sell_value = calculateSellValue(obj, tile);
    stats.set("Sells for", `<img src='img/ui/icons/icon_cash.png' class='icon-inline' alt='cash'>${fmt(Math.max(0, sell_value))}`);
  }
  if (obj.category === "particle_accelerator") {
    stats.set("EP scaling", "min(power sold, heat vented) / session");
  }
}

function getDetailedStats(obj, tile, game) {
  const stats = new Map();
  setMaxOrLockedStatus(stats, obj, game);
  setHeatAndSegmentStats(stats, obj, tile, game);
  setTransferSellAndEpStats(stats, obj, tile);
  return stats;
}

function buildDesktopSummaryItems(obj, tile) {
  const items = [];
  const summaryPower = tile?.display_power ?? obj.power ?? obj.base_power;
  const summaryHeat = tile?.display_heat ?? obj.heat ?? obj.base_heat;
  if (obj.cost !== undefined) items.push(`<span class='tooltip-summary-item'><img src='img/ui/icons/icon_cash.png' class='icon-inline' alt='cash'>${fmt(obj.cost)}</span>`);
  if (summaryPower > 0) items.push(`<span class='tooltip-summary-item'><img src='img/ui/icons/icon_power.png' class='icon-inline' alt='power'>${fmt(summaryPower)}</span>`);
  if (summaryHeat > 0) items.push(`<span class='tooltip-summary-item'><img src='img/ui/icons/icon_heat.png' class='icon-inline' alt='heat'>${fmt(summaryHeat, 0)}</span>`);
  if (obj.base_containment > 0 || obj.containment > 0) items.push(`<span class='tooltip-summary-item'><img src='img/ui/icons/icon_heat.png' class='icon-inline' alt='max heat'>Max: ${fmt(obj.base_containment || obj.containment, 0)}</span>`);
  if (obj.ticks > 0) items.push(`<span class='tooltip-summary-item'><img src='img/ui/icons/icon_time.png' class='icon-inline' alt='tick'>${fmt(obj.ticks)}</span>`);
  return items;
}

function formatCellSubstrateLines(tile, part) {
  if (!tile || part.category !== "cell") return "";
  const M = part.cell_pack_M ?? 1;
  const C = Math.max(1, part.cell_count_C ?? part.cell_count ?? 1);
  const N = computeNeighborPulseNFromTile(tile);
  const H = part.base_heat ?? 0;
  const P = part.base_power ?? 0;
  const heatVal = calculateCellPulseHeat(H, M, N, C);
  const powVal = calculateCellPulsePower(P, M, N);
  return `[P: ${fmt(P, 0)}] × ([M: ${M}] + [N: ${fmt(N, 0)}]) = ${fmt(powVal, 0)} Power/tick; [H: ${fmt(H, 0)}] × ([M: ${M}] + [N: ${fmt(N, 0)}])² / [C: ${C}] = ${fmt(heatVal, 0)} Heat/tick`;
}

function getBuyCostText(obj) {
  if (obj.current_ecost !== undefined) return ` 🧬 ${fmt(obj.current_ecost)} EP`;
  if (obj.ecost !== undefined) return ` 🧬 ${fmt(obj.ecost)} EP`;
  if (obj.base_ecost !== undefined) return ` 🧬 ${fmt(obj.base_ecost)} EP`;
  if (obj.current_cost !== undefined) return ` <img src='img/ui/icons/icon_cash.png' class='icon-inline' alt='cash'>${fmt(obj.current_cost)}`;
  if (obj.cost !== undefined) return ` <img src='img/ui/icons/icon_cash.png' class='icon-inline' alt='cash'>${fmt(obj.cost)}`;
  return "";
}

function tooltipContentTemplate(obj, tile, game, onBuy) {
  if (!obj) return html``;
  const iconify = getIconifyFn();
  const title = obj.title || obj.upgrade?.title || "";

  const summaryItems = buildDesktopSummaryItems(obj, tile);
  const summaryHtml = obj.upgrade ? summaryItems.join("") : "";
  let descHtml = "";
  if (obj.category === "cell" && !obj.upgrade && tile) {
    descHtml = formatDescriptionBulleted(formatCellSubstrateLines(tile, obj), iconify);
  } else if (!obj.upgrade) {
    descHtml = formatSemanticSegmentsForTooltip(collectPartSemanticSegments(obj, tile), fmt, iconify);
  } else {
    const description = obj.description || obj.upgrade?.description;
    descHtml = description ? formatDescriptionBulleted(description, iconify) : "";
  }
  const bonusLines = getUpgradeBonusLines(obj, tile, game);
  const bonusHtml = bonusLines.map((line) => `<div class="tooltip-bonus-line">${colorizeBonus(line, iconify)}</div>`).join("");
  const stats = getDetailedStats(obj, tile, game);
  const statsHtml = Array.from(stats.entries()).map(([k, v]) => `<dt>${iconify(k)}</dt><dd>${iconify(v)}</dd>`).join("");
  const buyBtn = obj.upgrade && obj.level < obj.max_level && onBuy ? html`<button class="" ?disabled=${!obj.affordable} @click=${onBuy}>Buy ${unsafeHTML(getBuyCostText(obj))}</button>` : "";
  return desktopTooltipContentTemplate({
    title,
    hasUpgrade: !!obj.upgrade,
    summaryHtml,
    descHtml,
    hasBonusLines: bonusLines.length > 0,
    bonusHtml,
    statsHtml,
    buyBtn,
  });
}

export class TooltipManager extends BaseComponent {
  constructor(main_element_selector, tooltip_element_selector, game) {
    super();
    this.$main = document.querySelector(main_element_selector);
    this.$tooltip = document.querySelector(tooltip_element_selector);
    this.$tooltipContent = document.getElementById("tooltip_data");
    this.game = game;

    if (!this.$main || !this.$tooltip || !this.$tooltipContent) {
      logger.log('error', 'ui', 'TooltipManager: A required element was not found.');
    }

    this.tooltip_task = null;
    this.tooltip_showing = false;
    this.current_obj = null;
    this.current_tile_context = null;
    this.isLocked = false;
    this.lastRenderedObj = null;
    this.lastRenderedTileContext = null;
    this._lastTooltipContent = null;
    this.isMobile = window.innerWidth <= MOBILE_BREAKPOINT_PX;
    this.needsLiveUpdates = false;
    this._resizeHandler = () => {
      const wasMobile = this.isMobile;
      this.isMobile = window.innerWidth <= MOBILE_BREAKPOINT_PX;
      if (this.isMobile) {
        this._hide();
        return;
      }
      if (wasMobile !== this.isMobile && this.current_obj) {
        this.update();
      }
    };
    this._tooltipClickHandler = (e) => {
      if (e.target.id === "tooltip_close_btn") this.closeView();
    };

    window.addEventListener("resize", this._resizeHandler);
    this.$tooltip.addEventListener("click", this._tooltipClickHandler);
  }

  teardown() {
    if (typeof window !== "undefined") {
      window.removeEventListener("resize", this._resizeHandler);
    }
    if (this.$tooltip) {
      this.$tooltip.removeEventListener("click", this._tooltipClickHandler);
    }
  }

  show(obj, tile_context, isClick = false, anchorEl = null) {
    if (this.isMobile) {
      this._hide();
      return;
    }
    if (this.isLocked && !isClick) return;
    clearTimeout(this.tooltip_task);

    if (!obj) {
      this.hide();
      return;
    }

    if (isClick) {
      this.isLocked = true;
    } else if (this.isLocked) {
      return;
    }

    this.current_obj = obj;
    this.current_tile_context = tile_context;
    this.needsLiveUpdates = this._shouldTooltipUpdateLive(obj, tile_context);
    const uiState = this.game?.ui?.uiState;
    if (uiState) uiState.hovered_entity = { obj, tile: tile_context, game: ref(this.game), isMobile: this.isMobile };

    if (!this.tooltip_showing) {
      this.isVisible = true;
      this.$main.classList.add("tooltip_showing");
      this.$tooltip.classList.remove("hidden");
      this.$tooltip.setAttribute("aria-hidden", "false");
      this.tooltip_showing = true;
    }

    if (
      this.lastRenderedObj !== obj ||
      this.lastRenderedTileContext !== tile_context
    ) {
      this.update();
      this.lastRenderedObj = obj;
      this.lastRenderedTileContext = tile_context;
    }

    clearDesktopTooltipPosition(this.$tooltip);
  }

  reposition() {
    if (this.tooltip_showing && this.current_obj && !this.isMobile) {
      clearDesktopTooltipPosition(this.$tooltip);
    }
  }

  hide() {
    if (this.isLocked) return;
    clearTimeout(this.tooltip_task);
    this.tooltip_task = setTimeout(() => {
      const uiState = this.game?.ui?.uiState;
      if (uiState) uiState.hovered_entity = null;
      else this._hide();
    }, 200);
    this.lastRenderedObj = null;
    this.lastRenderedTileContext = null;
  }

  closeView() {
    this.isLocked = false;
    this._hide();
  }

  forceHide() {
    this.isLocked = false;
    clearTimeout(this.tooltip_task);
    this.lastRenderedObj = null;
    this.lastRenderedTileContext = null;
    const uiState = this.game?.ui?.uiState;
    if (uiState?.hovered_entity) uiState.hovered_entity = null;
    else this._hide();
  }

  _hide() {
    this.current_obj = null;
    this.current_tile_context = null;
    if (this.tooltip_showing) {
      this.isVisible = false;
      this.$main.classList.remove("tooltip_showing");
      this.$tooltip.classList.add("hidden");
      this.$tooltip.setAttribute("aria-hidden", "true");
      this.tooltip_showing = false;
    }
  }

  async update() {
    this.game.performance.markStart("tooltip_update_total");
    if (!this.tooltip_showing || !this.current_obj) return;

    const onBuy = (e) => {
      e.preventDefault();
      e.stopPropagation();
      if (this.game.upgradeset.purchaseUpgrade(this.current_obj.id)) {
        actions.enqueueEffect(this.game, { kind: "sfx", id: "upgrade", context: "global" });
        this.update();
      } else {
        actions.enqueueEffect(this.game, { kind: "sfx", id: "error", context: "global" });
        actions.enqueueEffect(this.game, {
          kind: "floating_text",
          body: "[Not enough funds!]",
          context: "global",
        });
      }
    };
    const template = tooltipContentTemplate(this.current_obj, this.current_tile_context, this.game, onBuy);
    try {
      render(template, this.$tooltipContent);
    } catch (_) {}
    this.game.performance.markEnd("tooltip_update_total");
  }

  _shouldTooltipUpdateLive(obj, tile_context) {
    if (obj.upgrade) {
      return false;
    }
    if (tile_context && tile_context.activated) {
      return true;
    }
    return false;
  }

  updateUpgradeAffordability() {
    if (this.tooltip_showing && this.current_obj?.upgrade && this.isLocked) {
      this.update();
    }
  }
}

export function wireTooltipManager(ui, game) {
  const manager = new TooltipManager("#main", "#tooltip", game);
  ui.tooltipManager = manager;
  const uiState = ui.uiState;
  const unsubs = [];
  if (uiState) {
    unsubs.push(subscribeKey(uiState, "is_melting_down", (melting) => {
      if (melting) manager.forceHide();
    }));
    unsubs.push(subscribeKey(uiState, "hovered_entity", (entity) => {
      if (!entity?.obj) {
        if (manager.tooltip_showing) manager._hide();
        return;
      }
      if (manager.current_obj !== entity.obj || manager.current_tile_context !== entity.tile) {
        manager.show(entity.obj, entity.tile, !!entity.isClick);
      }
    }));
  }
  return () => {
    unsubs.forEach((fn) => { try { fn(); } catch (_) {} });
    manager.teardown();
    ui.tooltipManager = null;
  };
}

const VALID_LEVELS = ['error', 'warn', 'info', 'debug'];

export class Logger {
  constructor() {
    this.levels = { ERROR: 0, WARN: 1, INFO: 2, DEBUG: 3 };
    this.mutedContexts = new Set();
    this.productionMode = typeof window !== 'undefined' && window.PRODUCTION_BUILD === true;
    this.currentLevel = this.levels.INFO;
    if (typeof process !== 'undefined' && process.env.NODE_ENV === 'development') this.currentLevel = this.levels.DEBUG;
    if (!this.productionMode) {
      try {
        const storedLevel = localStorage.getItem('reactor_log_level');
        if (storedLevel && this.levels[storedLevel.toUpperCase()] !== undefined) this.currentLevel = this.levels[storedLevel.toUpperCase()];
      } catch (e) {}
    }
  }
  setLevel(level) {
    if (this.levels[level.toUpperCase()] !== undefined) {
      this.currentLevel = this.levels[level.toUpperCase()];
      try { localStorage.setItem('reactor_log_level', level.toUpperCase()); } catch (e) {}
    }
  }
  shouldLog(level) {
    if (this.productionMode) return level <= this.levels.WARN;
    return this.currentLevel >= level;
  }
  _formatArgs(args) {
    const seen = new WeakSet();
    const replacer = (key, value) => {
      if (typeof value === 'object' && value !== null) {
        if (seen.has(value)) return '[Circular]';
        seen.add(value);
        if (value.constructor && value.constructor.name !== 'Object' && value.constructor.name !== 'Array') return `[${value.constructor.name}]`;
      }
      return value;
    };
    return args.map(arg => {
      if (typeof arg === 'object' && arg !== null) {
        try { return JSON.stringify(arg, replacer, 2); } catch (e) { return '[Unserializable Object]'; }
      }
      return arg;
    });
  }
  _log(levelName, level, message, ...args) {
    if (this.shouldLog(level)) {
      const timestamp = new Date().toISOString().split('T')[1].split('.')[0];
      const prefix = `[${timestamp}] [${levelName}]`;
      const formattedArgs = this._formatArgs(args);
      console[levelName.toLowerCase()](prefix, message, ...formattedArgs);
    }
  }
  log(level, context, message, ...args) {
    const lvl = typeof level === 'string' ? level.toLowerCase() : level;
    const ctx = typeof context === 'string' ? context.toLowerCase() : 'app';
    if (!VALID_LEVELS.includes(lvl) || !ctx) return;
    if (this.mutedContexts.has(ctx)) return;
    const levelName = lvl.toUpperCase();
    const levelVal = this.levels[levelName];
    if (levelVal === undefined) return;
    const contextPrefix = ctx !== 'app' ? `[${ctx.toUpperCase()}] ` : '';
    this._log(levelName, levelVal, contextPrefix + message, ...args);
  }
  setMutedContexts(contexts) { this.mutedContexts = new Set(contexts.map((c) => String(c).toLowerCase())); }
  muteContext(context) { this.mutedContexts.add(String(context).toLowerCase()); }
  unmuteContext(context) { this.mutedContexts.delete(String(context).toLowerCase()); }
  error(message, ...args) { this.log('error', 'app', message, ...args); }
  warn(message, ...args) { this.log('warn', 'app', message, ...args); }
  info(message, ...args) { this.log('info', 'app', message, ...args); }
  debug(message, ...args) { this.log('debug', 'app', message, ...args); }
  group(label) { if (this.shouldLog(this.levels.DEBUG)) console.group(label); }
  groupCollapsed(label) { if (this.shouldLog(this.levels.DEBUG)) console.groupCollapsed(label); }
  groupEnd() { if (this.shouldLog(this.levels.DEBUG)) console.groupEnd(); }
}

export const logger = new Logger();

if (typeof window !== "undefined" && import.meta.env?.DEV) {
  window.logger = logger;
  window.setLogLevel = (level) => {
    const validLevels = ['ERROR', 'WARN', 'INFO', 'DEBUG'];
    if (!validLevels.includes(level.toUpperCase())) { console.warn(`Invalid level. Use: ${validLevels.join(', ')}`); return; }
    logger.setLevel(level);
    console.log(`Log level set to: ${level}`);
  };
  window.setDebug = () => window.setLogLevel('DEBUG');
  window.setInfo = () => window.setLogLevel('INFO');
  window.setWarn = () => window.setLogLevel('WARN');
  window.setError = () => window.setLogLevel('ERROR');
  window.getLogLevel = () => ['ERROR', 'WARN', 'INFO', 'DEBUG'][logger.currentLevel];
}

import { render } from "lit-html";
import { subscribe, subscribeKey } from "../store.js";
import { isTestEnv } from "../simUtils.js";

function bindContainerKey(container) {
  if (typeof container === "string") return container;
  if (container == null) return null;
  if (typeof container === "object" && typeof container.id === "string" && container.id) {
    return container.id;
  }
  if (typeof container === "object" && typeof container.nodeType === "number" && container.nodeType === 1) {
    const id = `lit-host-${Math.random().toString(36).slice(2, 11)}`;
    container.id = id;
    return id;
  }
  return null;
}

function isValidRenderTarget(node) {
  return (
    node &&
    typeof node === "object" &&
    node.nodeType === 1 &&
    node.tagName !== "TEMPLATE" &&
    typeof node.appendChild === "function" &&
    node.isConnected === true
  );
}

function resolveLiveContainer(containerKey) {
  if (typeof document === "undefined" || containerKey == null) return null;
  try {
    const node = document.getElementById(containerKey) ?? null;
    return isValidRenderTarget(node) ? node : null;
  } catch {
    return null;
  }
}

function isIgnorableLitRenderError(err) {
  const msg = String(err?.message ?? "");
  if ((msg.includes("parentNode") || msg.includes("nextSibling")) && msg.includes("null")) return true;
  return msg.includes("HTMLTemplateElement");
}

function scheduleLitRender(executeRender, rafRef) {
  if (rafRef.current) return;
  if (isTestEnv()) {
    executeRender();
    return;
  }
  rafRef.current = requestAnimationFrame(() => {
    rafRef.current = null;
    executeRender();
  });
}

export function bindLitRender(state, renderFn, container, onAfterRender) {
  const containerKey = bindContainerKey(container);
  const rafRef = { current: null };

  const executeRender = () => {
    const target = resolveLiveContainer(containerKey);
    if (!target) return;
    try {
      render(renderFn(state), target);
      onAfterRender?.();
    } catch (err) {
      if (isIgnorableLitRenderError(err)) return;
      console.error("Lit render error:", err);
    }
  };

  const scheduleRender = () => scheduleLitRender(executeRender, rafRef);
  const unsubscribe = subscribe(state, scheduleRender);
  executeRender();

  return () => {
    unsubscribe();
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
  };
}

export function bindLitRenderMultiStates(states, renderFn, container, onAfterRender) {
  const containerKey = bindContainerKey(container);
  const rafRef = { current: null };

  const executeRender = () => {
    const target = resolveLiveContainer(containerKey);
    if (!target) return;
    try {
      render(renderFn(), target);
      onAfterRender?.();
    } catch (err) {
      if (isIgnorableLitRenderError(err)) return;
      console.error("Lit render error:", err);
    }
  };

  const scheduleRender = () => scheduleLitRender(executeRender, rafRef);
  const unsubs = states.map((s) => subscribe(s, scheduleRender));
  executeRender();

  return () => {
    unsubs.forEach((fn) => { try { fn(); } catch (_) {} });
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
  };
}

export function bindLitRenderMulti(subscriptions, renderFn, container, onAfterRender) {
  const containerKey = bindContainerKey(container);
  const rafRef = { current: null };

  const executeRender = () => {
    const target = resolveLiveContainer(containerKey);
    if (!target) return;
    try {
      const template = renderFn();
      if (template) render(template, target);
      onAfterRender?.();
    } catch (err) {
      if (isIgnorableLitRenderError(err)) return;
      console.error("Lit render error:", err);
    }
  };

  const scheduleRender = () => scheduleLitRender(executeRender, rafRef);
  const unsubs = [];
  for (const { state, keys } of subscriptions) {
    const keyList = Array.isArray(keys) ? keys : [keys];
    for (const key of keyList) {
      unsubs.push(subscribeKey(state, key, scheduleRender));
    }
  }

  const initialTarget = resolveLiveContainer(containerKey);
  if (initialTarget) executeRender();

  return () => {
    unsubs.forEach((fn) => { try { fn(); } catch (_) {} });
    if (rafRef.current) cancelAnimationFrame(rafRef.current);
  };
}

export function bindLitRenderKeyed(state, stateKeys, renderFn, container) {
  const keys = Array.isArray(stateKeys) ? stateKeys : [stateKeys];
  return bindLitRenderMulti([{ state, keys }], () => renderFn(state), container);
}

import { render as litRender } from "../../lib/lit-html.js";
import { classMap as litClassMap } from "../../lib/lit-class-map.js";
import { styleMap as litStyleMap } from "../../lib/lit-style-map.js";
import { repeat as litRepeat } from "../../lib/lit-repeat.js";
import { when as litWhen } from "../../lib/lit-when.js";
import { unsafeHTML as litUnsafeHTML } from "../../lib/lit-unsafe-html.js";

export const render = litRender;
export const classMap = litClassMap;
export const styleMap = litStyleMap;
export const repeat = litRepeat;
export const when = litWhen;
export const unsafeHTML = litUnsafeHTML;

export function escapeHtml(text) {
  if (typeof text !== 'string') return text;
  return text.replace(/[&<>"']/g, (m) => ({
    '&': '&amp;',
    '<': '&lt;',
    '>': '&gt;',
    '"': '&quot;',
    "'": '&#39;'
  }[m]));
}

export function bindEvents(container, eventMap, { signal } = {}) {
  const owned = !signal;
  const controller = owned ? new AbortController() : null;
  const addOpts = { signal: signal ?? controller.signal };
  for (const [selector, config] of Object.entries(eventMap)) {
    const handlers = typeof config === "function" ? { click: config } : config;
    const elements = container.querySelectorAll(selector);
    elements.forEach((el) => { for (const [eventType, fn] of Object.entries(handlers)) el.addEventListener(eventType, fn, addOpts); });
  }
  if (owned) return () => controller.abort();
}

export const on = (parentElement, selector, eventType, handler) => {
  if (!parentElement) return () => {};
  const listener = (event) => {
    const targetElement = event.target.closest(selector);
    if (targetElement && parentElement.contains(targetElement)) handler.call(targetElement, event);
  };
  parentElement.addEventListener(eventType, listener);
  return () => parentElement.removeEventListener(eventType, listener);
};

export function resolveDomElement(node, fallbackId = null) {
  if (typeof document === "undefined") return null;
  let id = fallbackId;
  if (!id && node != null) {
    try {
      id = node.id;
    } catch {
      id = null;
    }
  }
  if (typeof id === "string" && id) return document.getElementById(id);
  return null;
}

export function getDomElementById(id) {
  if (!id || typeof document === "undefined") return null;
  return document.getElementById(id);
}

export class BaseComponent {
  constructor() {
    this.isVisible = false;
    this.teardown = () => {};
    this.show = () => {};
    this.hide = () => {};
  }
  setElementVisible(el, visible) {
    if (!el?.classList) return;
    el.classList.toggle("hidden", !visible);
  }
  removeOverlay(el) {
    if (el) el.remove();
    return null;
  }
}

export const performance = (typeof window !== 'undefined' && window.performance) || { now: () => new Date().getTime() };

export function getBasePath() {
  if (typeof window === 'undefined' || !window.location || !window.location.hostname) return '';
  try {
    const isGitHubPages = window.location.hostname && window.location.hostname.includes('github.io');
    if (isGitHubPages && window.location.pathname) {
      const pathParts = window.location.pathname.split('/');
      const repoName = pathParts.length > 1 && pathParts[1] ? pathParts[1] : '';
      return repoName ? `/${repoName}` : '';
    }
  } catch (_) {}
  return '';
}

export function getResourceUrl(resourcePath) {
  const basePath = getBasePath();
  if (resourcePath.startsWith('/')) return `${basePath}${resourcePath}`;
  return `${basePath}/${resourcePath}`;
}

import { bundledGameData } from "../bundledStaticData.js";
import { AchievementListSchema } from "../schema/index.js";
import { logger } from "../core/logger.js";
import { subscribe } from "valtio/vanilla";
import { subscribeKey } from "valtio/vanilla/utils";
import {
  evaluateTickCheck,
  TICK_CHECK_THRESHOLDS,
  STATEFUL_TICK_CHECKS,
} from "../logic/achievement-checks.js";
import { enqueueGameEffect } from "../state/game-effects.js";

function loadAchievementsFromBundle() {
  return AchievementListSchema.parse(bundledGameData.achievements);
}

export class AchievementManager {
  constructor(game) {
    this.game = game;
    this.achievements_data = [];
    this.trackers = new Map();
    this.pendingTickChecks = new Set();
    this._checkIdToAchievementIds = new Map();
    this._eventToAchievementIds = new Map();
    this._silentUnlockCount = 0;
    this._wasCatchingUp = false;
    this._explosionsThisTick = 0;
    this._unsubs = [];
  }

  async initialize() {
    this.achievements_data = loadAchievementsFromBundle();
    this._buildIndexes();
    this._rebuildPendingTickChecks();
    logger.log("debug", "game", `AchievementManager initialized with ${this.achievements_data.length} achievements`);
  }

  _buildIndexes() {
    this._checkIdToAchievementIds.clear();
    this._eventToAchievementIds.clear();
    for (let i = 0; i < this.achievements_data.length; i++) {
      const def = this.achievements_data[i];
      if (def.triggerType === "tick" && def.checkId) {
        const list = this._checkIdToAchievementIds.get(def.checkId) ?? [];
        list.push(def.id);
        this._checkIdToAchievementIds.set(def.checkId, list);
        if (TICK_CHECK_THRESHOLDS[def.checkId] != null || STATEFUL_TICK_CHECKS.has(def.checkId)) {
          if (!this.trackers.has(def.checkId)) {
            this.trackers.set(def.checkId, { consecutiveTicks: 0 });
          }
        }
      }
      if (def.triggerType === "event" && def.triggerEvent) {
        const list = this._eventToAchievementIds.get(def.triggerEvent) ?? [];
        list.push(def.id);
        this._eventToAchievementIds.set(def.triggerEvent, list);
      }
    }
  }

  _rebuildPendingTickChecks() {
    this.pendingTickChecks.clear();
    const unlocked = this._getUnlockedSet();
    for (let i = 0; i < this.achievements_data.length; i++) {
      const def = this.achievements_data[i];
      if (def.triggerType === "tick" && def.checkId && !unlocked.has(def.id)) {
        this.pendingTickChecks.add(def.checkId);
      }
    }
  }

  _getUnlockedSet() {
    const arr = this.game?.state?.unlocked_achievements;
    return new Set(Array.isArray(arr) ? arr : []);
  }

  _getUnlockedList() {
    const arr = this.game?.state?.unlocked_achievements;
    return Array.isArray(arr) ? arr : [];
  }

  isUnlocked(id) {
    return this._getUnlockedSet().has(id);
  }

  getDefinition(id) {
    return this.achievements_data.find((a) => a.id === id) ?? null;
  }

  restore(savedIds) {
    if (!this.game?.state) return;
    const ids = Array.isArray(savedIds) ? savedIds.filter((x) => typeof x === "string") : [];
    this.game.state.unlocked_achievements = ids;
    this._rebuildPendingTickChecks();
  }

  _isCatchUpSilent() {
    return !!this.game?.engine?._isCatchingUp;
  }

  unlock(id, { silent } = {}) {
    if (!id || this.isUnlocked(id)) return false;
    const def = this.getDefinition(id);
    if (!def) return false;

    const list = this._getUnlockedList();
    list.push(id);
    this.game.state.unlocked_achievements = list;

    if (def.checkId) this.pendingTickChecks.delete(def.checkId);

    const isSilent = silent ?? this._isCatchUpSilent();
    if (isSilent) {
      this._silentUnlockCount++;
    } else {
      enqueueGameEffect(this.game, {
        kind: "notice",
        tag: "ACHIEVEMENT",
        body: `Unlocked: ${def.title}`,
      });
    }

    if (this.game?.saveManager && !this.game._isRestoringSave) {
      void this.game.saveManager.autoSave();
    }
    return true;
  }

  onCatchUpEnded() {
    const count = this._silentUnlockCount;
    this._silentUnlockCount = 0;
    if (count > 0) {
      this.game.emit?.("achievementCatchUpSummary", { count });
    }
  }

  _handleCatchUpTransition() {
    const catchingUp = this._isCatchUpSilent();
    if (this._wasCatchingUp && !catchingUp) {
      this.onCatchUpEnded();
    }
    this._wasCatchingUp = catchingUp;
  }

  onTickRecorded() {
    if (!this.game) return;
    this._handleCatchUpTransition();
    const explosionTracker = this.trackers.get("simultaneous_explosions_10");
    if (explosionTracker) {
      explosionTracker.lastTickExplosions = this._explosionsThisTick;
    }
    this._explosionsThisTick = 0;
    if (this.pendingTickChecks.size === 0) return;
    const silent = this._isCatchUpSilent();
    const toUnlock = [];
    for (const checkId of this.pendingTickChecks) {
      const tracker = this.trackers.get(checkId) ?? { consecutiveTicks: 0 };
      if (evaluateTickCheck(this.game, checkId, tracker)) {
        const ids = this._checkIdToAchievementIds.get(checkId) ?? [];
        for (let i = 0; i < ids.length; i++) {
          if (!this.isUnlocked(ids[i])) toUnlock.push(ids[i]);
        }
      }
    }
    for (let i = 0; i < toUnlock.length; i++) {
      this.unlock(toUnlock[i], { silent });
    }
  }

  _tryUnlockEventAchievements(eventName, predicate) {
    const ids = this._eventToAchievementIds.get(eventName) ?? [];
    const silent = this._isCatchUpSilent();
    for (let i = 0; i < ids.length; i++) {
      const id = ids[i];
      if (this.isUnlocked(id)) continue;
      if (predicate && !predicate(id)) continue;
      this.unlock(id, { silent });
    }
  }

  _onMeltdownStarted() {
    this._tryUnlockEventAchievements("meltdownStarted");
  }

  _onComponentExplosion() {
    this._explosionsThisTick++;
    this._tryUnlockEventAchievements("component_explosion");
  }

  _onBlueprintPlannerChanged() {
    if (this._blueprintAchieveTimer) clearTimeout(this._blueprintAchieveTimer);
    this._blueprintAchieveTimer = setTimeout(async () => {
      this._blueprintAchieveTimer = null;
      const res = await this.game.requestBlueprintProjectionSample?.();
      const stats = res?.projectionPlannerSample;
      if (!stats || stats.stats_net_heat > 0 || stats.stats_power <= 0) return;
      this._tryUnlockEventAchievements("blueprintPlannerChanged");
    }, 150);
  }

  _onPrestigeCompleted(payload) {
    if (!payload?.keepEp) return;
    this._tryUnlockEventAchievements("prestigeCompleted", (id) => {
      if (id === "ach_nuclear_disarmament") {
        return (payload.fuelCellCount ?? 0) === 1;
      }
      if (id === "ach_perfect_weave") {
        const power = Number(payload.sessionPowerProduced ?? 0);
        const heat = Number(payload.sessionHeatDissipated ?? 0);
        if (power <= 0 || heat <= 0) return false;
        const spread = Math.abs(power - heat);
        const basis = Math.max(power, heat);
        return spread / basis <= 0.001;
      }
      return false;
    });
  }

  bind() {
    this.unbind();
    const g = this.game;
    if (!g?.on) return;

    const handlers = [
      ["component_explosion", () => this._onComponentExplosion()],
      ["prestigeCompleted", (p) => this._onPrestigeCompleted(p)],
    ];

    for (let i = 0; i < handlers.length; i++) {
      const [event, fn] = handlers[i];
      g.on(event, fn);
      this._unsubs.push(() => g.off?.(event, fn));
    }
    if (g.blueprintPlanner) {
      this._unsubs.push(subscribe(g.blueprintPlanner, () => this._onBlueprintPlannerChanged()));
    }
    if (g.state) {
      let lastMeltdownSeq = g.state.meltdown_seq | 0;
      this._unsubs.push(subscribeKey(g.state, "meltdown_seq", (seq) => {
        const n = seq | 0;
        if (n > lastMeltdownSeq) {
          lastMeltdownSeq = n;
          this._onMeltdownStarted();
        }
      }));
      this._unsubs.push(subscribeKey(g.state, "engine_tick_count", () => this.onTickRecorded()));
    }
  }

  unbind() {
    for (let i = 0; i < this._unsubs.length; i++) {
      try {
        this._unsubs[i]();
      } catch (_) {}
    }
    this._unsubs.length = 0;
  }

  start() {
    if (!this.achievements_data.length) {
      void this.initialize().then(() => this.bind());
      return;
    }
    this.bind();
  }
}

import { debitMoney, debitExoticParticles, enqueueDebitLayoutCost } from "./economy-intents.js";
import { BlueprintSchema, LegacyGridSchema } from "../store.js";
import { isLayoutShareCode, shareCodeToLayoutGrid } from "../core/layoutShareCodec.js";

export function clipToGrid(layout, rows, cols) {
  return layout.slice(0, rows).map((row) => (row || []).slice(0, cols));
}

export function getCostBreakdown(layout, partset) {
  if (!layout || !partset) return { money: 0, ep: 0 };
  return layout.flatMap((row) => row || []).filter((cell) => cell?.id).reduce(
    (out, cell) => {
      const part = partset.parts.get(cell.id);
      if (!part) return out;
      const n = (part.cost?.toNumber?.() ?? Number(part.cost ?? 0)) * (cell.lvl || 1);
      if (part.erequires) out.ep += n;
      else out.money += n;
      return out;
    },
    { money: 0, ep: 0 }
  );
}

function partCostForCell(part, cell, partset) {
  if (!part) return { money: 0, ep: 0 };
  const ecost = part.ecost;
  const usesEp = !!part.erequires;
  const base = usesEp && ecost?.gt?.(0)
    ? (ecost?.toNumber?.() ?? Number(ecost ?? 0))
    : (part.cost?.toNumber?.() ?? Number(part.cost ?? 0));
  const n = base * (cell.lvl || 1);
  if (usesEp) return { money: 0, ep: n };
  return { money: n, ep: 0 };
}

function cellsMatch(livePart, liveLvl, cell) {
  if (!cell?.id) return !livePart;
  if (!livePart) return false;
  return livePart.id === cell.id && (liveLvl || 1) === (cell.lvl || 1);
}

export function liveGridToLayout(game) {
  if (!game?.tileset) return null;
  const rows = game.rows;
  const cols = game.cols;
  const layout = Array.from({ length: rows }, () => Array.from({ length: cols }, () => null));
  game.tileset.tiles_list.forEach((tile) => {
    if (!tile.enabled || !tile.part) return;
    layout[tile.row][tile.col] = {
      id: tile.part.id,
      t: tile.part.type,
      lvl: tile.part.level || 1,
    };
  });
  return layout;
}

export function layoutFromPlannerSlots(game) {
  const slots = game.blueprintPlanner?.slots;
  if (!slots || typeof slots !== "object") return null;
  const rows = game.rows;
  const cols = game.cols;
  const layout = liveGridToLayout(game);
  if (!layout) return null;
  for (const key of Object.keys(slots)) {
    const partId = slots[key];
    if (!partId) continue;
    const [rs, cs] = key.split(",");
    const r = Number(rs);
    const c = Number(cs);
    if (!Number.isFinite(r) || !Number.isFinite(c) || r < 0 || c < 0 || r >= rows || c >= cols) continue;
    const part = game.partset.getPartById(partId);
    if (!part) continue;
    layout[r][c] = { id: part.id, t: part.type, lvl: part.level || 1 };
  }
  return layout;
}

export function computeBlueprintDiff(game, targetLayout) {
  if (!game?.tileset || !targetLayout) {
    return { toRemove: [], toPlace: [], unchanged: [], breakdown: { money: 0, ep: 0 } };
  }
  const clipped = clipToGrid(targetLayout, game.rows, game.cols);
  const toRemove = [];
  const toPlace = [];
  const unchanged = [];
  const breakdown = { money: 0, ep: 0 };

  for (let r = 0; r < clipped.length; r++) {
    const row = clipped[r] || [];
    for (let c = 0; c < row.length; c++) {
      const cell = row[c];
      const tile = game.tileset.getTile(r, c);
      if (!tile?.enabled) continue;
      const livePart = tile.part;
      const liveLvl = livePart?.level || 1;
      if (cellsMatch(livePart, liveLvl, cell)) {
        unchanged.push({ r, c, cell });
        continue;
      }
      if (livePart) toRemove.push({ r, c, tile });
      if (cell?.id) {
        const part = game.partset.getPartById(cell.id);
        if (part) {
          toPlace.push({ r, c, cell, part, tile });
          const cost = partCostForCell(part, cell, game.partset);
          breakdown.money += cost.money;
          breakdown.ep += cost.ep;
        }
      }
    }
  }
  return { toRemove, toPlace, unchanged, breakdown };
}

export function applyBlueprintLayoutDiff(game, targetLayout, options = {}) {
  if (!game?.tileset || !game?.partset || !targetLayout) return { ok: false, reason: "invalid" };
  const diff = computeBlueprintDiff(game, targetLayout);
  let placements = diff.toPlace;
  if (options.partial) {
    placements = filterAffordablePlacements(game, placements, options.sellCredit ?? 0);
    if (placements.length === 0 && diff.toPlace.length > 0) {
      return { ok: false, reason: "deficit", breakdown: diff.breakdown };
    }
  } else if (!options.skipCostDeduction) {
    const deficit = checkAffordability(game, diff.breakdown, options.sellCredit ?? 0);
    if (deficit) return { ok: false, reason: "deficit", ...deficit, breakdown: diff.breakdown };
  }

  const placeKeys = new Set(placements.map((p) => `${p.r},${p.c}`));
  const clipped = clipToGrid(targetLayout, game.rows, game.cols);
  for (let i = 0; i < diff.toRemove.length; i++) {
    const { r, c, tile } = diff.toRemove[i];
    const key = `${r},${c}`;
    const targetCell = clipped[r]?.[c];
    const clearingToEmpty = !targetCell?.id;
    if (clearingToEmpty || placeKeys.has(key)) {
      if (tile.part) tile.clearPart();
    }
  }
  for (let i = 0; i < placements.length; i++) {
    const { tile, part } = placements[i];
    if (tile.part) tile.clearPart();
    tile.setPart(part);
  }

  if (!options.skipCostDeduction) {
    const placeBreakdown = placements.reduce(
      (out, { part, cell }) => {
        const cost = partCostForCell(part, cell, game.partset);
        out.money += cost.money;
        out.ep += cost.ep;
        return out;
      },
      { money: 0, ep: 0 }
    );
    if (placeBreakdown.money > 0 || placeBreakdown.ep > 0) {
      enqueueDebitLayoutCost(game, { money: placeBreakdown.money, ep: placeBreakdown.ep });
    }
  }

  return {
    ok: true,
    placed: placements.length,
    removed: diff.toRemove.length,
    partial: !!options.partial,
    breakdown: diff.breakdown,
  };
}

function toResourceNumber(value) {
  if (value != null && typeof value.toNumber === "function") return value.toNumber();
  return Number(value ?? 0);
}

function checkAffordability(game, breakdown, sellCredit = 0) {
  const netMoney = breakdown.money - sellCredit;
  const money = toResourceNumber(game.state.current_money);
  const ep = toResourceNumber(game.state.current_exotic_particles ?? 0);
  const moneyShort = netMoney > money ? netMoney - money : 0;
  const epShort = breakdown.ep > ep ? breakdown.ep - ep : 0;
  if (moneyShort > 0 || epShort > 0) return { moneyShort, epShort };
  return null;
}

function filterAffordablePlacements(game, placements, sellCredit = 0) {
  let money = toResourceNumber(game.state.current_money) + sellCredit;
  let ep = toResourceNumber(game.state.current_exotic_particles ?? 0);
  const affordable = [];
  for (let i = 0; i < placements.length; i++) {
    const entry = placements[i];
    const cost = partCostForCell(entry.part, entry.cell, game.partset);
    if (cost.ep > 0) {
      if (ep < cost.ep) continue;
      ep -= cost.ep;
    } else if (cost.money > 0) {
      if (money < cost.money) continue;
      money -= cost.money;
    }
    affordable.push(entry);
  }
  return affordable;
}

export function filterAffordablePlacementsForGame(game, placements, sellCredit = 0) {
  return filterAffordablePlacements(game, placements, sellCredit);
}

export function applyBlueprintLayout(game, layout, skipCostDeduction = false) {
  const result = applyBlueprintLayoutDiff(game, layout, { skipCostDeduction });
  if (!result.ok) return null;
  return clipToGrid(layout, game.rows, game.cols);
}

const SELL_VALUE_MULTIPLIER = 0.5;

function buildEmptyLayout(rows, cols) {
  return Array.from({ length: rows }, () => Array.from({ length: cols }, () => null));
}

function populateLayoutFromParts(layout, parts, rows, cols) {
  parts.forEach((part) => {
    if (part.r >= 0 && part.r < rows && part.c >= 0 && part.c < cols) {
      layout[part.r][part.c] = { t: part.t, id: part.id, lvl: part.lvl };
    }
  });
}

function parseLayoutFromBlueprint(parsed) {
  const { rows, cols } = parsed.size;
  const layout = buildEmptyLayout(rows, cols);
  populateLayoutFromParts(layout, parsed.parts, rows, cols);
  return layout;
}

export function deserializeReactor(str) {
  if (!str || typeof str !== "string") return null;
  const trimmed = str.trim();
  if (isLayoutShareCode(trimmed)) return null;
  try {
    const data = JSON.parse(trimmed);
    const bpResult = BlueprintSchema.safeParse(data);
    if (bpResult.success) return parseLayoutFromBlueprint(bpResult.data);
    const legacyResult = LegacyGridSchema.safeParse(data);
    if (legacyResult.success) return legacyResult.data;
    return null;
  } catch {
    return null;
  }
}

export function deserializeReactorInput(str, game) {
  if (!str || typeof str !== "string") return null;
  const trimmed = str.trim();
  if (isLayoutShareCode(trimmed) && game?.partset) {
    return shareCodeToLayoutGrid(trimmed, game.partset);
  }
  return deserializeReactor(trimmed);
}

export function parseClipboardString(raw, game) {
  const layout = deserializeReactorInput(raw, game);
  if (!layout) return { layout: null, error: "Invalid layout data" };
  return { layout, error: null };
}

function resourceGte(a, b) {
  return a != null && typeof a.gte === "function" ? a.gte(b) : Number(a) >= b;
}

function resourceSub(a, b) {
  return a != null && typeof a.sub === "function" ? a.sub(b) : a - b;
}

function normalizeMoney(game, sellCredit) {
  let money = game.state.current_money;
  if (money != null && typeof money.add === "function") return sellCredit > 0 ? money.add(sellCredit) : money;
  return Number(money?.toNumber?.() ?? money ?? 0) + sellCredit;
}

function normalizeEp(game) {
  const ep = game.state.current_exotic_particles ?? 0;
  if (ep && typeof ep.toNumber === "function") return ep.toNumber();
  return Number(ep ?? 0);
}

function getNormalizedResources(game, sellCredit) {
  return { money: normalizeMoney(game, sellCredit), ep: normalizeEp(game) };
}

function getPartCost(part, cell) {
  const cost = part.cost != null && part.cost.gte ? part.cost.mul(cell.lvl || 1) : (part.cost ?? 0) * (cell.lvl || 1);
  const costNum = typeof cost === "number" ? cost : (cost?.toNumber?.() ?? Number(cost));
  return { cost, costNum };
}

function allocateIfAffordable(money, ep, part, cost, costNum, gte, sub) {
  if (part.erequires) {
    if (gte(ep, costNum)) return { newMoney: money, newEp: typeof ep === "number" ? ep - costNum : sub(ep, cost), allocated: true };
    return { newMoney: money, newEp: ep, allocated: false };
  }
  if (gte(money, costNum)) return { newMoney: typeof money === "number" ? money - costNum : sub(money, cost), newEp: ep, allocated: true };
  return { newMoney: money, newEp: ep, allocated: false };
}

function getCellCostNumber(part, cell) {
  if (typeof part.cost === "undefined" || part.cost == null) return 0;
  const amount = part.cost.gte ? part.cost.mul(cell.lvl || 1) : part.cost * (cell.lvl || 1);
  return amount != null && amount.gte != null ? amount.toNumber?.() ?? Number(amount) : Number(amount);
}

function addCellCostToBreakdown(out, part, num) {
  if (part.erequires) out.ep += num;
  else out.money += num;
}

export function calculateLayoutCostBreakdown(partset, layout) {
  const out = { money: 0, ep: 0 };
  if (!layout || !partset) return out;
  const cells = layout.flatMap((row) => row || []);
  cells
    .filter((cell) => cell?.id)
    .forEach((cell) => {
      const part = partset.parts.get(cell.id);
      if (part) addCellCostToBreakdown(out, part, getCellCostNumber(part, cell));
    });
  return out;
}

export function calculateLayoutCost(partset, layout) {
  return calculateLayoutCostBreakdown(partset, layout).money;
}

export function calculateLayoutCostFromData(entryData, partset, fmtFn) {
  try {
    const str = typeof entryData === "string" ? entryData : JSON.stringify(entryData);
    const layout2D = deserializeReactor(str);
    if (!layout2D || !partset) return "-";
    const cost = layout2D.flatMap((row) => row || []).filter((cell) => cell?.id).reduce((sum, cell) => {
      const part = partset.parts.get(cell.id);
      if (!part) return sum;
      const c = part.cost?.toNumber?.() ?? Number(part.cost ?? 0);
      return sum + c * (cell.lvl || 1);
    }, 0);
    return cost > 0 ? fmtFn(cost) : "-";
  } catch {
    return "-";
  }
}

export function calculateLayoutDiffBreakdown(game, layout) {
  if (!game) return { money: 0, ep: 0 };
  const clipped = clipToGrid(layout, game.rows, game.cols);
  return computeBlueprintDiff(game, clipped).breakdown;
}

export function filterLayoutByCheckedTypes(layout, checkedTypes) {
  return layout.map((row) => row.map((cell) => (cell && checkedTypes[cell.id] !== false) ? cell : null));
}

export function calculateCurrentSellValue(tileset) {
  if (!tileset?.tiles_list) return 0;
  let sellValue = 0;
  tileset.tiles_list.forEach((tile) => {
    if (tile.enabled && tile.part) {
      sellValue += (tile.part.cost * (tile.part.level || 1)) * SELL_VALUE_MULTIPLIER;
    }
  });
  return Math.floor(sellValue);
}

export function buildAffordableLayout(filteredLayout, sellCredit, gameRows, gameCols, game) {
  if (!filteredLayout || !game?.partset) return null;
  let { money, ep } = getNormalizedResources(game, sellCredit);
  const rows = Math.min(gameRows, filteredLayout.length);
  const cols = Math.min(gameCols, filteredLayout[0]?.length ?? 0);
  const result = Array.from({ length: rows }, () => Array.from({ length: cols }, () => null));
  const cellsInOrder = filteredLayout.flatMap((row, r) =>
    (row || []).map((cell, c) => (cell && cell.id ? { r, c, cell } : null)).filter(Boolean)
  );
  cellsInOrder.forEach(({ r, c, cell }) => {
    const part = game.partset.getPartById(cell.id);
    if (!part) return;
    const { cost, costNum } = getPartCost(part, cell);
    const { newMoney, newEp, allocated } = allocateIfAffordable(money, ep, part, cost, costNum, resourceGte, resourceSub);
    money = newMoney;
    ep = newEp;
    if (allocated) result[r][c] = cell;
  });
  return result;
}

function calculateFinances(breakdown, sellCredit, currentMoneyNum, currentEpNum) {
  const netMoney = breakdown.money - sellCredit;
  const canAffordMoney = netMoney <= currentMoneyNum;
  const canAffordEp = breakdown.ep <= currentEpNum;
  const canPaste = (breakdown.money > 0 || breakdown.ep > 0) && canAffordMoney && canAffordEp;
  return { canAffordMoney, canAffordEp, canPaste };
}

export function buildPasteState(layout, checkedTypes, game, tileset, sellCheckboxChecked) {
  if (!layout) return { valid: false, invalidMessage: "Invalid layout data" };

  const filteredLayout = filterLayoutByCheckedTypes(layout, checkedTypes);
  const breakdown = game
    ? calculateLayoutDiffBreakdown(game, filteredLayout)
    : calculateLayoutCostBreakdown(game?.partset, filteredLayout);
  const sellCredit = sellCheckboxChecked ? calculateCurrentSellValue(tileset) : 0;

  const currentMoney = game.state.current_money;
  const currentEp = game.state.current_exotic_particles;
  const currentMoneyNum = typeof currentMoney?.toNumber === "function"
    ? currentMoney.toNumber()
    : Number(currentMoney ?? 0);
  const currentEpNum = typeof currentEp?.toNumber === "function"
    ? currentEp.toNumber()
    : Number(currentEp ?? 0);

  const finances = calculateFinances(breakdown, sellCredit, currentMoneyNum, currentEpNum);
  const diff = game ? computeBlueprintDiff(game, filteredLayout) : { toPlace: [] };
  const affordablePlacements = game
    ? filterAffordablePlacementsForGame(game, diff.toPlace, sellCredit)
    : [];
  const hasPartial = !finances.canPaste && affordablePlacements.length > 0;

  return {
    valid: true,
    filteredLayout,
    breakdown,
    ...finances,
    affordablePlacements,
    currentMoneyNum,
    currentEpNum,
    hasPartial,
  };
}

export function validatePasteResources(breakdown, sellCredit, currentMoney, currentEp) {
  const netMoney = breakdown.money - sellCredit;
  if (breakdown.money <= 0 && breakdown.ep <= 0) return { valid: false, reason: "no_parts" };
  if (!resourceGte(currentMoney, netMoney) || !resourceGte(currentEp, breakdown.ep)) return { valid: false, reason: "insufficient_resources" };
  return { valid: true };
}

export function computePastePreview(game, layout, options = {}) {
  const { checkedTypes = {}, sellExisting = false, tileset } = options;
  const state = buildPasteState(layout, checkedTypes, game, tileset ?? game?.tileset, sellExisting);
  if (!state.valid) return { ...state, diff: null, cost: null, affordable: false, partial: false };
  const diff = computeBlueprintDiff(game, state.filteredLayout);
  return {
    ...state,
    diff,
    cost: state.breakdown,
    affordable: state.canPaste,
    partial: state.hasPartial,
  };
}

