    const k = `${row},${col}`;
    if (!partId) delete this.blueprintPlanner.slots[k];
    else this.blueprintPlanner.slots[k] = partId;
    this._syncBlueprintPlannerUi();
  }

  _syncBlueprintPlannerUi() {
    const d = this.ui?.uiState?.copy_paste_display;
    if (d) d.blueprintPlannerActive = !!this.blueprintPlanner.active;
  }

  getBlueprintPlannerPartId(row, col) {
    return this.blueprintPlanner?.slots?.[`${row},${col}`] ?? null;
  }

  buildGridProjectionSnapshot() {
    const rows = this.rows;
    const cols = this.cols;
    const partIds = [];
    for (let r = 0; r < rows; r++) {
      for (let c = 0; c < cols; c++) {
        partIds.push(this.getBlueprintPlannerPartId(r, c));
      }
    }
    return { rows, cols, partIds };
  }

  requestBlueprintProjectionSample(options = {}) {
    return postGameLoopProjectionQuery(this.engine, this, options);
  }

  requestLayoutProjectionSample(layout, options = {}) {
    return postGameLoopProjectionQuery(this.engine, this, { ...options, layout });
  }

  applyBlueprintPlannerLayout(options = {}) {
    if (!this.engine) return null;
    this.state.intent_queue.push({
      action: "COMMIT_BLUEPRINT_PLANNER",
      payload: { partial: options.partial === true },
    });
    return this.engine.consumeIntentQueueAsync();
  }

  getDoctrine() {
    if (!this.tech_tree) return null;
    return this.upgradeset.techTrees?.find(t => t.id === this.tech_tree) || null;
  }

  respecDoctrine() {
    const cost = this.RESPER_DOCTRINE_EP_COST; // Ensure using the property name in class
    const currentEp = this.state.current_exotic_particles;

    if (currentEp.lt(cost)) return false;

    updateDecimal(this.state, "current_exotic_particles", (d) => d.sub(cost));

    const oldTree = this.tech_tree;
    this.tech_tree = null; // Set to null as per test expectation

    this.upgradeset.resetDoctrineUpgradeLevels(oldTree);
    resetHeatThresholdSignalState(this);

    if (this.saveManager) this.saveManager.autoSave();
    return true;
  }
}

import { MOBILE_BREAKPOINT_PX } from "../constants/ui-constants.js";
import {
  BASE_COLS_MOBILE,
  BASE_COLS_DESKTOP,
  BASE_ROWS_MOBILE,
  BASE_ROWS_DESKTOP,
} from "../constants/balance.js";
import { GameDimensionsSchema } from "../schema/index.js";

export function calculateBaseDimensions() {
  const isMobile = typeof window !== "undefined" && window.innerWidth <= MOBILE_BREAKPOINT_PX;
  const raw = {
    base_cols: isMobile ? BASE_COLS_MOBILE : BASE_COLS_DESKTOP,
    base_rows: isMobile ? BASE_ROWS_MOBILE : BASE_ROWS_DESKTOP,
  };
  return GameDimensionsSchema.parse(raw);
}

export class GridManager {
  constructor(game) {
    this.game = game;
    const dimensions = calculateBaseDimensions();
    this.base_cols = dimensions.base_cols;
    this.base_rows = dimensions.base_rows;
    this._rows = this.base_rows;
    this._cols = this.base_cols;
  }

  updateBaseDimensions() {
    const dimensions = calculateBaseDimensions();
    const oldBaseCols = this.base_cols;
    const oldBaseRows = this.base_rows;
    this.base_cols = dimensions.base_cols;
    this.base_rows = dimensions.base_rows;
    if (this.game.rows === oldBaseRows && this.game.cols === oldBaseCols) {
      this.setRows(this.base_rows);
      this.setCols(this.base_cols);
      return;
    }
    const rowDiff = this.base_rows - oldBaseRows;
    const colDiff = this.base_cols - oldBaseCols;
    if (rowDiff !== 0 || colDiff !== 0) {
      this.setRows(Math.max(this.base_rows, this._rows + rowDiff));
      this.setCols(Math.max(this.base_cols, this._cols + colDiff));
    }
  }

  setRows(value) {
    if (this._rows !== value) {
      const oldRows = this._rows;
      this._rows = value;
      if (this.game.tileset && typeof this.game.tileset.resize === "function") {
        this.game.tileset.resize(value, this._cols);
      } else {
        this.game.tileset.updateActiveTiles();
      }
      this.game.reactor.updateStats();
      this.game.ui?.resizeReactor?.();
    }
  }

  setCols(value) {
    if (this._cols !== value) {
      const oldCols = this._cols;
      this._cols = value;
      if (this.game.tileset && typeof this.game.tileset.resize === "function") {
        this.game.tileset.resize(this._rows, value);
      } else {
        this.game.tileset.updateActiveTiles();
      }
      this.game.reactor.updateStats();
      this.game.ui?.resizeReactor?.();
    }
  }

  get rows() {
    return this._rows;
  }

  get cols() {
    return this._cols;
  }
}

