import { bundledGameData } from "./bundledStaticData.js";
import { compileTraitBitmask } from "./traits.js";

const PART_TEMPLATES = bundledGameData.parts;

function pow(a, b) {
  return (Number(a) || 1) ** (Number(b) || 0);
}

export function collectAllPartIds() {
  const ids = [];
  for (const p of PART_TEMPLATES) {
    if (typeof p.levels === "number" && p.levels > 0) {
      for (let L = 1; L <= p.levels; L++) ids.push(`${p.id}${L}`);
    } else {
      ids.push(p.id);
    }
  }
  return ids;
}

export function resolvePartTemplate(id) {
  const s = String(id);
  const exact = PART_TEMPLATES.find((p) => p.id === s);
  if (exact && exact.levels == null) {
    return { template: exact, level: exact.level ?? 1 };
  }
  const m = s.match(/^(.+?)(\d+)$/);
  if (!m) return null;
  const baseId = m[1];
  const n = parseInt(m[2], 10);
  const template = PART_TEMPLATES.find((p) => p.id === baseId && typeof p.levels === "number");
  if (!template || n < 1 || n > template.levels) return null;
  return { template, level: n };
}

export function buildPartDefFromCatalog(id) {
  const resolved = resolvePartTemplate(id);
  if (!resolved) return null;
  const { template: t, level } = resolved;

  const costMulti = t.cost_multi ?? 1;
  const baseCost = t.base_cost ?? 0;
  const cost = baseCost * pow(costMulti, level - 1);

  const out = {
    ...t,
    id,
    type: t.type,
    category: t.category,
    level,
    base_power: t.base_power ?? 0,
    base_heat: t.base_heat ?? 0,
    base_cost: baseCost,
    base_ecost: t.base_ecost ?? 0,
    ecost: t.base_ecost ?? 0,
    base_reactor_power: t.base_reactor_power ?? 0,
    base_reactor_heat: t.base_reactor_heat ?? 0,
    base_ep_heat: t.base_ep_heat ?? 0,
    base_vent: t.base_vent ?? 0,
    base_transfer: t.base_transfer ?? 0,
    base_power_increase: t.base_power_increase ?? 0,
    base_heat_increase: t.base_heat_increase ?? 0,
    perpetual: false,
    pBase: t.base_power ?? 0,
    hBase: t.base_heat ?? 0,
    packM: 1,
    cell_pack_M: 1,
    cell_count: t.id === "protium" ? 1 : 0,
    cost,
    transfer_multiplier: t.transfer_multiplier ?? 1,
  };

  out.containment = t.base_containment ?? (t.category === "coolant_cell" ? 2000 : (t.category === "vent" ? 80 : (t.category === "heat_exchanger" ? 320 : (t.category === "capacitor" ? 10 : 1000))));

  const MULTIPLIERS = [
    { base: 'base_ticks', mult: 'ticks_multiplier', norm: 1 },
    { base: 'base_vent', mult: 'vent_multiplier', norm: 75 },
    { base: 'base_transfer', mult: 'transfer_multiplier', norm: 75 },
    { base: 'base_reactor_power', mult: 'reactor_power_multi', norm: 140 },
    { base: 'base_reactor_heat', mult: 'reactor_heat_multiplier', norm: 150 },
    { base: 'base_containment', mult: 'containment_multiplier', norm: 1e6 },
    { base: 'base_containment', mult: 'containment_multi', norm: t.containment_norm ?? (t.category === 'capacitor' ? 5 : (t.category === 'coolant_cell' ? 180 : 75)) },
  ];

  for (let i = 0; i < MULTIPLIERS.length; i++) {
    const { base, mult, norm } = MULTIPLIERS[i];
    if (t[base] != null && t[mult] != null && level > 1) {
      out[base] = t[base] * pow(t[mult] / norm, level - 1);
    }
  }

  if (t.category === "cell" && level > 1) {
    const m = t.cost_multi ?? 2;
    out.base_power = (t.base_power ?? 0) * pow(m, level - 1);
    out.base_heat = (t.base_heat ?? 0) * pow(m, level - 1);
    out.pBase = out.base_power;
    out.hBase = out.base_heat;
  }

  const power_inc = (t.base_power_increase ?? 0) + (level > 1 && t.power_increase_add ? (level - 1) * t.power_increase_add : 0);
  const heat_inc = t.base_heat_increase ?? 0;
  const traits = (Array.isArray(t.traits) && t.traits.length > 0) ? t.traits : (t.category === "cell" ? ["FUEL_CELL"] : []);
  const trait_mask = compileTraitBitmask(traits);

  out.ticks = out.base_ticks ?? 100;
  out.power = out.base_power;
  out.heat = out.base_heat;
  out.vent = out.base_vent;
  out.transfer = out.base_transfer;
  if (out.base_containment != null) out.containment = out.base_containment;
  out.reactor_power = out.base_reactor_power;
  out.reactor_heat = out.base_reactor_heat;
  out.ep_heat = out.base_ep_heat;

  out.power_increase = power_inc;
  out.heat_increase = heat_inc;
  out.traits = traits;
  out.trait_mask = trait_mask;

  return out;
}

import { z } from "../../lib/zod.js";
import { toDecimal } from "../simUtils.js";

export const NumericLike = z.union([z.number(), z.string()]);

export const DecimalLike = z.union([
  z.number(),
  z.string(),
  z.custom((v) => v == null || (typeof v?.gte === "function")),
]);

export const GridCoordinate = z.number().int().min(0);

export const DecimalSchema = NumericLike.transform((v) => (v != null && v !== "" ? toDecimal(v) : toDecimal(0)));

function toSaveDecimal(value) {
  if (value == null || value === "") return toDecimal(0);
  try {
    const decimal = toDecimal(value);
    const num = decimal?.toNumber?.();
    return Number.isFinite(num) ? decimal : toDecimal(0);
  } catch {
    return toDecimal(0);
  }
}

export const SaveDecimalSchema = z
  .union([DecimalLike, z.undefined()])
  .transform((v) => toSaveDecimal(v));

export const ObjectiveIndexSchema = z
  .union([z.number(), z.string()])
  .optional()
  .transform((v) => {
    if (v === undefined || v === null) return 0;
    const n = parseInt(v, 10);
    return Number.isNaN(n) ? 0 : Math.max(0, Math.floor(n));
  });

export const NumericToNumber = DecimalLike.transform((v) => (v != null && v !== "" ? toDecimal(v).toNumber() : undefined));

export const SAVE_FORMAT_VERSION_LATEST = 2;
export const SAVE_FORMAT_VERSION_INITIAL = 1;

function bytesToBase64(bytes) {
  if (typeof Buffer !== "undefined") {
    return Buffer.from(bytes).toString("base64");
  }
  let binary = "";
  for (let i = 0; i < bytes.length; i++) binary += String.fromCharCode(bytes[i]);
  return btoa(binary);
}

function base64ToBytes(b64) {
  if (typeof Buffer !== "undefined") {
    return new Uint8Array(Buffer.from(b64, "base64"));
  }
  const binary = atob(b64);
  const out = new Uint8Array(binary.length);
  for (let i = 0; i < binary.length; i++) out[i] = binary.charCodeAt(i);
  return out;
}

export function buildPartTable(partset) {
  if (!partset?.partsArray?.length) {
    return { part_table: [""], idToIndex: new Map([["", 0]]) };
  }
  const ids = [...new Set(partset.partsArray.map((p) => p.id))].sort();
  const part_table = ["", ...ids];
  const idToIndex = new Map();
  part_table.forEach((id, i) => idToIndex.set(id, i));
  return { part_table, idToIndex };
}

export function encodeTilesCompact(tileList, rows, cols, idToIndex) {
  const n = rows * cols;
  const idBytes = new Uint8Array(n * 2);
  const tickBytes = new Uint8Array(n * 4);
  const heatBytes = new Uint8Array(n * 4);
  const idDv = new DataView(idBytes.buffer);
  const tickDv = new DataView(tickBytes.buffer);
  const heatDv = new DataView(heatBytes.buffer);
  for (let i = 0; i < n; i++) {
    idDv.setUint16(i * 2, 0, true);
    tickDv.setFloat32(i * 4, 0, true);
    heatDv.setFloat32(i * 4, 0, true);
  }
  for (const t of tileList || []) {
    const r = t.row;
    const c = t.col;
    if (r == null || c == null || r < 0 || c < 0 || r >= rows || c >= cols) continue;
    const idx = r * cols + c;
    const pid = t.partId ?? t.id;
    if (!pid) continue;
    const pi = idToIndex.get(pid);
    if (pi == null || pi === 0) continue;
    idDv.setUint16(idx * 2, pi, true);
    tickDv.setFloat32(idx * 4, Number(t.ticks) || 0, true);
    heatDv.setFloat32(idx * 4, Number(t.heat_contained) || 0, true);
  }
  return {
    encoding: "u16_f32f32",
    rows,
    cols,
    ids_b64: bytesToBase64(idBytes),
    ticks_b64: bytesToBase64(tickBytes),
    heat_b64: bytesToBase64(heatBytes),
  };
}

export function decodeTilesCompact(tiles_compact, part_table) {
  if (!tiles_compact || tiles_compact.encoding !== "u16_f32f32") return [];
  const { rows, cols, ids_b64, ticks_b64, heat_b64 } = tiles_compact;
  if (!rows || !cols || !ids_b64 || !ticks_b64 || !heat_b64 || !part_table?.length) return [];
  const n = rows * cols;
  const idBytes = base64ToBytes(ids_b64);
  const tickBytes = base64ToBytes(ticks_b64);
  const heatBytes = base64ToBytes(heat_b64);
  if (idBytes.byteLength < n * 2 || tickBytes.byteLength < n * 4 || heatBytes.byteLength < n * 4) return [];
  const idDv = new DataView(idBytes.buffer, idBytes.byteOffset, n * 2);
  const tickDv = new DataView(tickBytes.buffer, tickBytes.byteOffset, n * 4);
  const heatDv = new DataView(heatBytes.buffer, heatBytes.byteOffset, n * 4);
  const out = [];
  for (let i = 0; i < n; i++) {
    const pi = idDv.getUint16(i * 2, true);
    if (!pi) continue;
    const partId = part_table[pi];
    if (!partId) continue;
    const row = (i / cols) | 0;
    const col = i % cols;
    out.push({
      row,
      col,
      partId,
      ticks: tickDv.getFloat32(i * 4, true) || 0,
      heat_contained: heatDv.getFloat32(i * 4, true) || 0,
    });
  }
  return out;
}

function normalizeLegacyGrid2D(data) {
  const out = { ...data };
  if (out.tiles && Array.isArray(out.tiles) && out.tiles.length > 0) {
    const first = out.tiles[0];
    if (Array.isArray(first)) {
      const migrated = [];
      (out.tiles || []).forEach((row, r) => {
        (row || []).forEach((cell, c) => {
          if (cell && (cell.partId || cell.id)) {
            migrated.push({
              row: r,
              col: c,
              partId: cell.partId ?? cell.id,
              ticks: cell.ticks ?? 0,
              heat_contained: cell.heat_contained ?? 0,
            });
          }
        });
      });
      out.tiles = migrated;
    }
  }
  return out;
}

export function migrateSave(raw) {
  if (!raw || typeof raw !== "object") return raw;
  let data = normalizeLegacyGrid2D({ ...raw });
  if (!data.version) data.version = "1.0.0";
  const ver = typeof data.save_format_version === "number" && data.save_format_version >= 1
    ? data.save_format_version
    : SAVE_FORMAT_VERSION_INITIAL;
  if (ver < SAVE_FORMAT_VERSION_LATEST) {
    data.save_format_version = SAVE_FORMAT_VERSION_LATEST;
  } else {
    data.save_format_version = ver;
  }
  const compact = data.tiles_compact;
  const table = data.part_table;
  const tilesArr = Array.isArray(data.tiles) ? data.tiles : [];
  if (compact && Array.isArray(table) && table.length > 0 && tilesArr.length === 0) {
    data.tiles = decodeTilesCompact(compact, table);
  }
  return data;
}

