import { ref } from "valtio/vanilla";
import { toDecimal, toNumber } from "../simUtils.js";

export function updateDecimal(state, key, fn) {
  const current = state[key];
  const decimal = (current != null && typeof current.gte === "function") ? current : toDecimal(current ?? 0);
  state[key] = ref(fn(decimal));
}

export function setDecimal(state, key, value) {
  if (state?._simulationLocked && (key === "current_money" || key === "current_exotic_particles")) {
    return;
  }
  state[key] = ref(toDecimal(value));
}

// Centralized state synchronization from reactor to UI state
// This reduces parallel state mirroring by providing a single function to sync reactor values
export function syncReactorToUIState(game) {
  if (!game?.state || !game.reactor) return;

  const reactor = game.reactor;
  // Sync heat and power values
  setDecimal(game.state, "current_heat", reactor.current_heat);
  setDecimal(game.state, "current_power", reactor.current_power);

  // Sync max values if they exist
  if (reactor.max_heat != null) game.state.max_heat = toNumber(reactor.max_heat);
  if (reactor.max_power != null) game.state.max_power = toNumber(reactor.max_power);

  // Sync computed stats
  if (reactor.stats_power != null) game.state.stats_power = reactor.stats_power;
  if (reactor.stats_heat_generation != null) game.state.stats_heat_generation = reactor.stats_heat_generation;
  if (reactor.stats_total_part_heat != null) game.state.stats_total_part_heat = reactor.stats_total_part_heat;
  if (reactor.stats_vent != null) game.state.stats_vent = reactor.stats_vent;
  if (reactor.stats_inlet != null) game.state.stats_inlet = reactor.stats_inlet;
  if (reactor.stats_outlet != null) game.state.stats_outlet = reactor.stats_outlet;
  if (reactor.stats_cash != null) game.state.stats_cash = reactor.stats_cash;
  if (reactor.stats_net_heat != null) game.state.stats_net_heat = reactor.stats_net_heat;
}

import { MutationObserver } from "@tanstack/query-core";
import { SaveDataSchema, SaveDataWriteSchema } from "../schema/index.js";
import { queryClient, queryKeys } from "../services-query.js";
import {
  StorageAdapter,
  serializeSave,
  rotateSlot1ToBackup,
  AUTOSAVE_SLOT_KEY,
  STORAGE_KEYS,
} from "../storage/index.js";
import { logger } from "../core/logger.js";
import { formatDuration, formatStatNum } from "../format/numbers.js";

const LOCAL_SLOTS = [1, 2, 3];

async function performSave(slot, saveData) {
  const forDisk = { ...saveData };
  if (forDisk.tiles_compact?.encoding && Array.isArray(forDisk.part_table) && forDisk.part_table.length > 0) {
    forDisk.tiles = [];
  }
  const validatedData = SaveDataWriteSchema.parse(forDisk);
  const saveKey = slot === "auto" ? AUTOSAVE_SLOT_KEY : `${STORAGE_KEYS.GAME_SAVE}_${slot}`;
  await StorageAdapter.set(saveKey, validatedData);
  if (slot === 1) {
    await rotateSlot1ToBackup(serializeSave(validatedData));
  }
  if (slot !== "auto") {
    await StorageAdapter.set(STORAGE_KEYS.CURRENT_SLOT, slot);
  }
  return slot;
}

export function createSaveMutation() {
  return new MutationObserver(queryClient, {
    mutationFn: async ({ slot, saveData }) => performSave(slot, saveData),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: queryKeys.saves.resolved() });
    },
    onError: (error) => {
      logger.log("error", "game", "Save mutation failed:", error);
    },
  });
}

export async function saveGameMutation({ slot, saveData, getNextSaveSlot, isAutoSave = false }) {
  if (typeof indexedDB === "undefined") return null;
  if (typeof process !== "undefined" && process.env?.NODE_ENV === "test") return null;

  const effectiveSlot = isAutoSave ? "auto" : (slot ?? (await getNextSaveSlot()));
  await performSave(effectiveSlot, saveData);
  queryClient.invalidateQueries({ queryKey: queryKeys.saves.resolved() });
  return effectiveSlot;
}

async function fetchLocalSlotData(slotId) {
  try {
    const slotData = await StorageAdapter.get(`${STORAGE_KEYS.GAME_SAVE}_${slotId}`, SaveDataSchema);
    if (!slotData) return null;
    return {
      slot: slotId,
      exists: true,
      lastSaveTime: slotData.last_save_time || null,
      totalPlayedTime: slotData.total_played_time || 0,
      currentMoney: slotData.current_money || 0,
      exoticParticles: slotData.exotic_particles ?? slotData.total_exotic_particles ?? 0,
      data: slotData,
      isAutoSave: false,
    };
  } catch (error) {
    logger.log("warn", "saves", `Failed to fetch local slot ${slotId}`, error);
    return null;
  }
}

async function fetchAutoSaveSlotData() {
  try {
    const slotData = await StorageAdapter.get(AUTOSAVE_SLOT_KEY, SaveDataSchema);
    if (!slotData) return null;
    return {
      slot: "auto",
      exists: true,
      lastSaveTime: slotData.last_save_time || null,
      totalPlayedTime: slotData.total_played_time || 0,
      currentMoney: slotData.current_money || 0,
      exoticParticles: slotData.exotic_particles ?? slotData.total_exotic_particles ?? 0,
      data: slotData,
      isAutoSave: true,
    };
  } catch (error) {
    logger.log("warn", "saves", "Failed to fetch autosave buffer", error);
    return null;
  }
}

async function fetchLegacySlotData() {
  try {
    const oldSaveData = await StorageAdapter.get(STORAGE_KEYS.GAME_SAVE, SaveDataSchema);
    if (!oldSaveData) return null;
    return {
      slot: "legacy",
      exists: true,
      lastSaveTime: oldSaveData.last_save_time || null,
      totalPlayedTime: oldSaveData.total_played_time || 0,
      currentMoney: oldSaveData.current_money || 0,
      exoticParticles: oldSaveData.exotic_particles ?? oldSaveData.total_exotic_particles ?? 0,
      data: oldSaveData,
      isAutoSave: false,
    };
  } catch (error) {
    logger.log("warn", "saves", "Failed to fetch legacy save", error);
    return null;
  }
}

async function fetchResolvedSavesFn() {
  const slotPromises = LOCAL_SLOTS.map(fetchLocalSlotData);
  const results = await Promise.all(slotPromises);
  const saveSlots = results.filter(Boolean);
  const autoSave = await fetchAutoSaveSlotData();

  if (saveSlots.length === 0) {
    const legacy = await fetchLegacySlotData();
    if (legacy) saveSlots.push(legacy);
  }

  const hasSave = saveSlots.length > 0 || !!autoSave;
  let maxLocalTime = 0;
  let mostRecentSlot = null;

  for (const slot of saveSlots) {
    const t = slot.lastSaveTime || 0;
    if (t > maxLocalTime) {
      maxLocalTime = t;
      mostRecentSlot = slot;
    }
  }
  if (autoSave && (autoSave.lastSaveTime || 0) > maxLocalTime) {
    mostRecentSlot = autoSave;
  }

  let dataJSON = null;
  if (mostRecentSlot) {
    if (mostRecentSlot.slot === "legacy") {
      dataJSON = await StorageAdapter.getRaw(STORAGE_KEYS.GAME_SAVE);
    } else if (mostRecentSlot.slot === "auto") {
      dataJSON = await StorageAdapter.getRaw(AUTOSAVE_SLOT_KEY);
    } else {
      dataJSON = await StorageAdapter.getRaw(`${STORAGE_KEYS.GAME_SAVE}_${mostRecentSlot.slot}`);
    }
  }

  let mostRecentSave = null;
  let recentTime = 0;
  for (const saveSlot of saveSlots) {
    if (saveSlot.lastSaveTime && saveSlot.lastSaveTime > recentTime) {
      recentTime = saveSlot.lastSaveTime;
      mostRecentSave = saveSlot;
    }
  }
  if (autoSave && (autoSave.lastSaveTime || 0) > recentTime) {
    mostRecentSave = autoSave;
  }

  return {
    hasSave,
    saveSlots,
    autoSave,
    cloudSaveOnly: false,
    cloudSaveData: null,
    mostRecentSave,
    maxLocalTime: Math.max(maxLocalTime, autoSave?.lastSaveTime || 0),
    dataJSON,
  };
}

export function fetchResolvedSaves() {
  return queryClient.fetchQuery({
    queryKey: queryKeys.saves.resolved(),
    queryFn: fetchResolvedSavesFn,
    staleTime: 10 * 1000,
  });
}

export function getSaveStats(data) {
  if (!data || typeof data !== "object") {
    return { money: "0", ep: "0", playtime: "0", timestamp: "Unknown" };
  }
  const money = data.current_money != null ? formatStatNum(data.current_money) : "0";
  const ep =
    data.exotic_particles != null
      ? formatStatNum(data.exotic_particles)
      : data.total_exotic_particles != null
        ? formatStatNum(data.total_exotic_particles)
        : "0";
  const playtime = data.total_played_time != null ? formatDuration(data.total_played_time, false) : "0";
  const ts = data.last_save_time;
  const timestamp = ts ? new Date(Number(ts)).toLocaleString() : "Unknown";
  return { money, ep, playtime, timestamp };
}

